/* factions q03 (110 mục) — engine-API đợt 361-363 Ch.363 */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q03"]=window.__LIBQ["pham-nhan-tu-tien"]["q03"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q03"]["factions"]={"updatedAt":"2026-07-09","count":110,"factions":[{"id":"thanh-hu-mon","name":"Thanh Hư môn","cn":null,"type":"tong-mon","typeLabel":"Tông môn — đạo sĩ","diaBan":"Việt quốc (một trong thất đại phái)","nhanVatChinh":["Phù Vân Tử (dẫn đoàn)"],"blurb":"Một trong thất đại phái Việt quốc. Đặc trưng: đệ tử mặc đạo bào xám, đa số là đạo sĩ chân chính (cầm phất trần đội đạo kế), số ít tục gia đệ tử. Sở hữu pháp khí phi hành Tuyết Hồng Lăng. Người dẫn đầu Kết Đan kỳ là Phù Vân Tử.","detail":"Xuất hiện c175–c179: Phù Vân Tử dẫn đoàn Thanh Hư môn đến điểm hẹn Kiến Châu trên Tuyết Hồng Lăng. Xác nhận c177: một trong thất đại phái Việt quốc, lập trường trung lập (không chính không tà), ngàn năm trước liên thủ với các phái diệt chính-tà.","nguon":["c0175","c0176","c0177","c0178","c0179"]},{"id":"yen-nguyet-tong","name":"Yểm Nguyệt tông","cn":null,"type":"tong-mon","typeLabel":"Tông môn — song tu","diaBan":"Việt quốc (một trong thất đại phái)","nhanVatChinh":["Nghê Thường (dẫn đoàn)","Khung tiền bối (quan sát)"],"blurb":"Một trong thất đại phái Việt quốc, tu theo Song tu thuật — cần đệ tử nữ dung mạo thượng đẳng song tu cùng đệ tử nam. Đệ tử trẻ đều từng đôi. Sở hữu pháp khí phi hành Thiên Nguyệt thần chu. Được xem là lối tu có phần tà lạc theo quan niệm chính phái.","detail":"Xuất hiện c177–c179: Khung tiền bối đại diện đề xuất ván cược ba bên; Nghê Thường tiên tử trực tiếp dẫn đoàn. Xác nhận c177–c178: một trong thất đại phái Việt quốc. Lý Sư Tổ giải thích về Song tu thuật và lý do chọn đệ tử nữ dung mạo thượng đẳng.","nguon":["c0176","c0177","c0178","c0179"]},{"id":"linh-thu-son","name":"Linh Thú Sơn","cn":null,"type":"tong-mon","typeLabel":"Tông môn — linh thú sư","diaBan":"Việt quốc (một trong thất đại phái)","nhanVatChinh":["Vu sư huynh","nữ đệ tử cô gái bán Kim Trúc Bút"],"blurb":"Một trong thất đại phái Việt quốc. Đặc trưng dùng linh thú chiến đấu, mang túi da đựng linh thú. Sở hữu kỹ thuật Khu thú phấn khống chế yêu thú. Trong Huyết Cấm Thí Luyện, một số đệ tử thể hiện thủ đoạn tàn độc (Vu sư huynh dụ-giết đồng môn phái khác).","detail":"Xuất hiện c178–c180: Linh Thú Sơn đến điểm hẹn Kiến Châu trong đoàn. C179: nữ đệ tử xinh đẹp (cô gái bán Kim Trúc Bút cũ) nhận ra Hàn Lập; gã râu quai nón ức hiếp nàng. C180: Vu sư huynh dùng Khu thú phấn + Băng trùy thuật + Hàn băng thiềm giết đệ tử Thiên Khuyết Bảo tại Ô Long đàm.","nguon":["c0178","c0179","c0180","@c0181","@c0211","@c0255","@c0271","@c0340"],"tabs":{"tienTrinh":[{"chuong":"@c0340","loai":"nhắc tới","importance":"major","giaiDoan":"Nghi vấn phản kích nội bộ","text":"Linh Thú sơn bị đặt vào vị trí có thể quay ngược đánh vào trận thế liên quân, tạo thời cơ cho Ma đạo phá đại trận.","anchor":"đem Linh Thú sơn quay ngược đâm một kích, tất nhiên có thể dễ dàng xé rách trận thế của liên quân","trangThaiMoc":"Bị tố cấu kết Ma đạo"}]},"trangThai":"Bị nghi cấu kết Ma đạo @c0340"},{"id":"cu-kiem-mon","name":"Cự Kiếm Môn","cn":null,"type":"tong-mon","typeLabel":"Tông môn — kiếm tu","diaBan":"Việt quốc (một trong thất đại phái)","nhanVatChinh":[],"blurb":"Một trong thất đại phái Việt quốc. Đặc trưng: toàn nam tử mặc hắc y, mang cự kiếm lớn, thần sắc lãnh khốc đầy sát khí. Đến điểm hẹn Kiến Châu tham gia Huyết Cấm Thí Luyện.","detail":"Xuất hiện c178–c179: Cự Kiếm Môn là một trong bốn phái còn lại (cùng Linh Thú Sơn, Hóa Đao Ổ, Thiên Khuyết Bảo) tham gia Huyết Cấm Thí Luyện. Mô tả: toàn nam tử hắc y, đeo cự kiếm, lãnh khốc sát khí theo quan sát của Hàn Lập.","nguon":["c0178","c0179","@c0181","@c0211","@c0213","@c0259","@c0357"],"tabs":{"tienTrinh":[{"chuong":"@c0357","loai":"nhắc tới","importance":"normal","giaiDoan":"Giữ trọng địa","text":"Cự Kiếm môn được nêu cùng Yểm Nguyệt tông là trọng địa còn chưa bị Ma đạo công phá sau biến cố Việt quốc.","anchor":"ngoại trừ Yểm Nguyệt tông cùng Cự Kiếm môn còn chưa bị công phá","trangThaiMoc":"chưa bị công phá"}]},"trangThai":"trọng địa chưa bị công phá"},{"id":"hoa-dao-o","name":"Hóa Đao Ổ","cn":null,"type":"tong-mon","typeLabel":"Tông môn — đao tu","diaBan":"Việt quốc (một trong thất đại phái)","nhanVatChinh":[],"blurb":"Một trong thất đại phái Việt quốc. Đặc trưng phục sức khác lạ, vũ khí liên quan đến đao. Đến điểm hẹn Kiến Châu tham gia Huyết Cấm Thí Luyện.","detail":"Xuất hiện c178–c179: Hóa Đao Ổ là một trong bốn phái còn lại tham gia Huyết Cấm Thí Luyện. Phục sức khác lạ theo quan sát của Hàn Lập. Không có nhân vật nào được nêu tên từ môn phái này trong đợt nghiên cứu.","nguon":["c0178","c0179","@c0185","@c0199","@c0272"]},{"id":"thien-khuyet-bao","name":"Thiên Khuyết Bảo","cn":null,"type":"tong-mon","typeLabel":"Tông môn — pháp bảo","diaBan":"Việt quốc (một trong thất đại phái)","nhanVatChinh":[],"blurb":"Một trong thất đại phái Việt quốc. Đặc trưng phục sức khác lạ; pháp bảo bản mệnh dạng đại ấn vàng. Đệ tử bị Vu sư huynh (Linh Thú Sơn) dụ-giết trong Huyết Cấm Thí Luyện.","detail":"Xuất hiện c178–c180: một trong bốn phái còn lại tham gia Huyết Cấm. C179: đại ấn vàng được Hàn Lập quan sát là pháp bảo bản mệnh đặc trưng. C180: đệ tử Thiên Khuyết Bảo bị Vu sư huynh nhóm Linh Thú Sơn dụ tới Ô Long đàm rồi giết bằng Khu thú phấn + Băng trùy thuật + Hàn băng thiềm.","nguon":["c0178","c0179","c0180","@c0181","@c0211","@c0255"]},{"id":"hoang-phong-coc","name":"Hoàng Phong cốc","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Không rõ","nhanVatChinh":["Hàn Lập"],"blurb":"Tông môn của Hàn Lập, có đệ tử tham gia Huyết sắc thí luyện.","detail":"Tông môn Hàn Lập đang theo học. Trong chương, hắn phát hiện thi thể một sư huynh đệ Hoàng Phong cốc áo vàng, y phục giống hắn như đúc, đã dùng ti tuyến đánh lén đối phương nhưng bị đâm chết cùng lúc trong trận tử chiến dưới vách núi.","nguon":["@c0181","@c0242"],"aliases":["Hoàng phong cốc"]},{"id":"van-bao-cac","name":"Vạn bảo các","type":"the-luc-buon-ban","typeLabel":"Thế lực buôn bán","blurb":"Thế lực buôn bán, nơi Hàn Lập mua Kim quang chuyên.","detail":"Hàn Lập mua phù bảo Kim quang chuyên từ Vạn bảo các; khi bị phù bảo hút pháp lực, hắn mắng Vạn bảo các đã bán “quỷ hút máu chết người”.","nguon":["@c0184"]},{"id":"yem-nguyet-tong","name":"Yểm nguyệt tông","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Không rõ","nhanVatChinh":["Nữ đệ tử Yểm nguyệt tông","Nam Cung Bình","Nam Cung Uyển"],"blurb":"Tông môn của nữ đệ tử bị Hàn Thiên Nhai lừa giết bên dòng suối trong cấm địa.","detail":"Tông môn xuất hiện qua một nữ đệ tử tham gia huyết sắc thí luyện; nữ đệ tử này bị Hàn Thiên Nhai giết bằng thủ đoạn lừa gạt sau khi dùng nhan sắc cầu sống.","nguon":["@c0185","@c0263","@c0362"],"tabs":{"tienTrinh":[{"chuong":"@c0362","loai":"nhắc tới","importance":"normal","giaiDoan":"Được Nam Cung Bình đề cập","text":"Nam Cung Bình nêu Yểm Nguyệt Tông là bổn tông của mình và dùng các bí thuật của tông môn để dụ Hàn Lập chọn phương án thứ hai.","anchor":"Yểm Nguyệt Tông chúng ta với Hoàng Phong Cốc tạp phái các ngươi hoàn toàn bất đồng"}]},"trangThai":"đang hoạt động","thanhVien":[{"ten":"Nam Cung Bình","chucVu":"Nữ tu Kết Đan kỳ","tuChuong":"@c0362","trangThai":"đang thuộc tông"},{"ten":"Nam Cung Uyển","chucVu":"Tu sĩ liên quan Yểm Nguyệt Tông","tuChuong":"@c0362","trangThai":"được nhắc liên hệ qua Nam Cung Bình"}]},{"id":"that-dai-phai","name":"Thất đại phái","cn":"七大派","type":"lien-minh","typeLabel":"Liên minh tông môn","diaBan":"","nhanVatChinh":["Phong Nhạc"],"blurb":"Bối cảnh nơi Phong Nhạc hoành hành, ác danh lan xa trong đám đệ tử cấp thấp.","detail":"Thất đại phái là bối cảnh nơi Phong Nhạc hoành hành sau khi Trúc Cơ không thành. Dựa vào vài món pháp khí không tệ và thủ đoạn hung độc, hung danh của Phong Nhạc lan xa trong đám đệ tử cấp thấp, khiến hắn duy ngã độc tôn, càng thêm hung hãn điên cuồng.","nguon":["@c0188"]},{"id":"tran-thi-gia-toc","name":"Trần thị gia tộc","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Không rõ","nhanVatChinh":["Trần đại công tử","Trần sư muội"],"blurb":"Siêu cấp gia tộc họ Trần. Trần đại công tử là đại công tử của gia tộc, Trần thất muội là em gái.","detail":"Siêu cấp gia tộc họ Trần, có thế lực lớn khiến các phe kiêng nể. Trần đại công tử — đại công tử của gia tộc — và Trần thất muội (em gái) đang tranh đoạt linh thảo trong cấm địa và truy tìm người cứu thất muội qua manh mối Thanh Giao kỳ.","nguon":["@c0199"]},{"id":"bon-mon-han-lap-dia-hoa","name":"Bổn môn (tông môn của Hàn Lập)","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Việt quốc","nhanVatChinh":["Hàn Lập","Đại hán ngốc nghếch (dẫn đường Địa Hỏa Chi Ốc)"],"blurb":"Tông môn sở hữu khu Địa Hỏa Chi Ốc dùng để luyện khí luyện đan.","detail":"Tông môn của Hàn Lập, sở hữu khu Địa Hỏa Chi Ốc và dựng tổng cộng ba mươi sáu gian địa hỏa để môn nhân luyện khí luyện đan. Trong đó gian mười tám và mười chín là tốt nhất; gian mười tám do một vị sư bá chiếm dùng.","nguon":["@c0214"]},{"id":"huyen-kiem-mon","name":"Huyền kiếm môn","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Không rõ (đã bị diệt)","nhanVatChinh":["Môn chủ Huyền kiếm môn"],"blurb":"Môn phái đã bị Hoàng phong cốc tiêu diệt nhiều năm trước; Thanh nguyên kiếm quyết là tuyệt học trấn phái của môn này.","detail":"Một môn phái từng có tuyệt học trấn phái là Thanh nguyên kiếm quyết mười ba tầng, đã bị Hoàng phong cốc tiêu diệt nhiều năm về trước. Khi sắp diệt môn, Môn chủ Huyền kiếm môn hủy kiếm quyết ngay tại đương trường, nhưng vài vị sư tổ Hoàng phong cốc cướp được nửa bộ, nửa còn lại bị hủy thất truyền, khiến bản Hoàng phong cốc lưu truyền chỉ là bản thiếu.","nguon":["@c0217"]},{"id":"ky-lan-cac","name":"Kỳ lân các","cn":"","type":"khac","typeLabel":"Bộ phận tông môn","diaBan":"Linh thú sơn","nhanVatChinh":["Nữ đệ tử Kỳ lân các"],"blurb":"Bộ phận của Hoàng phong cốc phụ trách Linh thú sơn, cho thuê linh thú.","detail":"Kỳ lân các là tổ chức thuộc Hoàng phong cốc phụ trách Linh thú sơn, cho các tu sĩ thuê linh thú. Đệ tử Kỳ lân các thay phiên tuần dưỡng gần ngàn con linh thú nuôi trong các khối cấm chế phong bế; chỉ đệ tử của các mới được ra vào các khu này. Nghênh khách đài là nơi các tiếp khách và giao thú thuê.","nguon":["@c0220"]},{"id":"thien-tinh-tong","name":"Thiên tinh tông","cn":"","type":"tong-mon","typeLabel":"Tông môn tu tiên","diaBan":"Nguyên Vũ quốc","nhanVatChinh":[],"blurb":"Đại phái tu tiên của Nguyên Vũ quốc, lập phường thị giằng co với Hoàng phong cốc.","detail":"Thiên tinh tông là một tu tiên đại phái của Nguyên Vũ quốc. Tông môn này thiết lập một phường thị cạnh tranh giằng co với phường thị của Hoàng phong cốc. Hàn Lập chọn khai mở động phủ gần phường thị Thiên tinh tông để tiện mua bán mà không bị người bổn môn nhận ra.","nguon":["@c0220","@c0221","@c0352"],"tabs":{"tienTrinh":[{"chuong":"@c0352","loai":"nhắc tới","importance":"normal","giaiDoan":"Phường thị đông bất thường","text":"Phường thị của Thiên Tinh Tông được Hàn Lập ghé tới và có lượng tu sĩ giao dịch tăng mạnh, bao gồm không ít tu sĩ Trúc Cơ kỳ.","trangThaiMoc":"đang hoạt động","anchor":"đi tới phường thị của Thiên Tinh Tông"}]},"trangThai":"đang hoạt động"},{"id":"tu-gia","name":"Từ gia","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Phường thị nhỏ (Thiên Tinh Tông)","nhanVatChinh":["Từ lão giả"],"blurb":"Gia tộc của Từ lão giả, nắm giữ bí thuật luyện khí bằng yêu hỏa nhờ ngẫu nhiên sở hữu một con hỏa nha.","detail":"Gia tộc luyện khí bàng môn tả đạo. Mấy trăm năm qua Từ gia chỉ cần nhị cấp sơ giai đã có thể phun ra yêu hỏa lợi hại hơn tiên thiên chân hỏa vài phần, dùng để luyện chế pháp khí và đan dược. Sở dĩ có được năng lực này là nhờ ngẫu nhiên có một con hỏa nha. Kỹ thuật này không được các đại phái thừa nhận và bị truyền bá nghiêm ngặt.","nguon":["@c0222"]},{"id":"bi-diem-canh-mai-hoi","name":"Bí điếm (cạnh mại hội)","cn":"","type":"khac","typeLabel":"Điếm ngầm","diaBan":"Cách phường thị Thiên Tinh Tông một dặm, ẩn sau một gian hàng bình thường","nhanVatChinh":["Trương phu nhân"],"blurb":"Điếm ngầm mở một lần mỗi tháng, ẩn sau gian hàng bình thường, có địa đạo và hắc y hộ vệ Trúc cơ kỳ, chuyên bán tinh phẩm nhiều vật có vấn đề về lai lịch.","detail":"Bí điếm cách phường thị một dặm, vào qua địa đạo dài mười trượng từ một gian hàng nhỏ do Trương phu nhân coi giữ, hai bên cửa đá có hai hắc y nhân đeo mặt nạ ác quỷ (một người ở Trúc Cơ trung kỳ). Đại sảnh ngầm hình tròn xa hoa quy tụ hơn nửa tu sĩ từ Trúc cơ kỳ trở lên, tổ chức đấu giá do ba người che mặt chủ trì: điếm ra giá trước, khách đấu giá tự do, thiếu linh thạch có thể dùng vật phẩm thay thế.","nguon":["@c0223"]},{"id":"thien-truc-giao","name":"Thiên Trúc giáo","cn":"","type":"tong-mon","typeLabel":"Tông phái","diaBan":"Vùng đất cực tây","nhanVatChinh":[],"blurb":"Tông phái ở vùng đất cực tây lấy khôi lỗi cơ quan thuật khai môn lập phái.","detail":"Thiên Trúc giáo là tông phái tại vùng đất cực tây, lấy khôi lỗi cơ quan thuật làm gốc để khai môn lập phái và phát huy đạo thuật luyện chế này tới cực điểm. Thành phẩm khôi lỗi cơ quan nhân của họ có thể ganh đua với tu sĩ Trúc Cơ kỳ hậu kỳ.","nguon":["@c0224","@c0264","@c0265"]},{"id":"van-bao-lau","name":"Vạn Bảo lâu","cn":"","type":"the-luc","typeLabel":"Thế lực","diaBan":"Không rõ","nhanVatChinh":[],"blurb":"Nơi Hàn Lập từng bán hai gốc Hoàng Tinh chi ngàn năm do chính hắn nuôi dưỡng; một trong các gốc nay xuất hiện tại buổi đấu giá bí điếm.","detail":"Thế lực buôn bán vật phẩm tu tiên nơi Hàn Lập từng đem bán hai gốc Hoàng Tinh chi ngàn năm. Đến chương này, một trong hai gốc linh dược đó lại xuất hiện tại buổi đấu giá kín của bí điếm, được Hàn Lập nhận ra ngay khi đưa ra sàn.","nguon":["@c0225"]},{"id":"than-binh-mon","name":"Thần Binh Môn","cn":"","aliases":[],"type":"chinh-phai","typeLabel":"Chánh phái","diaBan":"Nguyên Vũ Quốc","nhanVatChinh":["Tề Vân Tiêu"],"blurb":"Một trong Nguyên Vũ Quốc tam đại chánh phái, nổi tiếng về luyện khí thuật; ngang hàng Thiên Tinh Tông và Vạn Diệu Quan.","detail":"Một trong ba đại chánh phái của Nguyên Vũ Quốc, nổi tiếng về luyện khí thuật khắp tu tiên giới các quốc gia lân cận, đứng ngang hàng với Thiên Tinh Tông (trận pháp) và Vạn Diệu Quan (phù đạo). Gia tổ của Tề Vân Tiêu từng là Luyện khí trưởng lão của môn phái, luyện khí đạt cực đỉnh.","nguon":["@c0227"]},{"id":"van-dieu-quan","name":"Vạn Diệu Quan","cn":"","aliases":[],"type":"chinh-phai","typeLabel":"Chánh phái","diaBan":"Nguyên Vũ Quốc","nhanVatChinh":[],"blurb":"Một trong Nguyên Vũ Quốc tam đại chánh phái, nổi tiếng về phù đạo.","detail":"Một trong ba đại chánh phái của Nguyên Vũ Quốc, nổi tiếng về phù đạo, đứng ngang hàng với Thần Binh Môn (luyện khí) và Thiên Tinh Tông (trận pháp).","nguon":["@c0227"]},{"id":"nguyen-vu-quoc-tu-tien-gioi","name":"Nguyên Vũ Quốc (tu tiên giới / các gia môn)","cn":"","aliases":[],"type":"the-luc","typeLabel":"Tu tiên giới","diaBan":"Nguyên Vũ Quốc","nhanVatChinh":["Tu sĩ lớn tuổi (gia môn Nguyên Vũ Quốc, bị vây)","Tu sĩ trẻ tuổi (gia môn Nguyên Vũ Quốc, bị vây)"],"blurb":"Tu tiên giới của quốc gia Nguyên Vũ, gồm nhiều gia môn phái đệ tử đi hoạt động. Đám tu sĩ bị vây tự nhận là đệ tử các gia môn, dùng danh nghĩa này đe dọa họa sát thân.","detail":"Quốc gia mà đám tu sĩ bị nam tử khôi vũ vây khốn tự nhận là đệ tử các gia môn phái đi. Họ dùng danh nghĩa toàn thể tu tiên giới Nguyên Vũ Quốc làm lời đe dọa họa sát thân, nhưng nam tử khôi vũ đến từ Thiên Trúc Giáo nên không sợ đắc tội.","nguon":["@c0229","@c0265"]},{"id":"co-doc-tong","name":"Cổ Độc Tông","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Không rõ","nhanVatChinh":[],"blurb":"Tông môn chuyên về cổ độc, nơi Hoàng Long phải ngàn cay vạn đắng mới cầu được Hắc Ti Cổ.","detail":"Cổ Độc Tông là tông môn chuyên luyện độc và cổ trùng. Hoàng Long đã phải ngàn cay vạn đắng mới cầu được Hắc Ti Cổ từ nơi này để dùng làm mắt xích then chốt trong bẫy hạ độc Lâm sư huынh.","nguon":["@c0230","@c0233"]},{"id":"bi-diem-che-tao-khoi-loi","name":"Bí điếm (bí tiệm chế tạo khôi lỗi)","type":"the-luc","typeLabel":"Thế lực","diaBan":"Không rõ","nhanVatChinh":[],"blurb":"Nơi chế tạo khôi lỗi đã phối hợp với Thiên Trúc Giáo vì lợi ích, bán đứng Lâm sư huynh trong bẫy Đại Diễn Quyết.","detail":"Bí điếm là nơi làm khôi lỗi. Vì lợi ích, nơi này đã phối hợp với Thiên Trúc Giáo để tung tin giả về nửa phần Đại Diễn Quyết giấu trong khôi lỗi thú, góp phần dụ Lâm sư huынh sa vào bẫy diệt trừ.","nguon":["@c0230"]},{"id":"mon-ha-ly-hoa-nguyen","name":"Môn hạ Lý Hóa Nguyên","type":"su-mon","typeLabel":"Sư môn","diaBan":"Lục Ba động","nhanVatChinh":["Lý Hóa Nguyên","Vu Khôn","Tống Mông","Hàn Lập"],"blurb":"Nhóm đệ tử dưới trướng Lý Hóa Nguyên, gồm Vu Khôn (Đại sư huynh), Tống Mông (Tứ sư huynh), Hàn Lập (sắp làm Bát sư đệ) và năm sư huynh đệ khác có động phủ riêng bên ngoài.","detail":"Ngoài vợ chồng Lý Hóa Nguyên, chỉ Vu Khôn và Tống Mông ở lại Lục Ba động vì từ nhỏ lớn lên bên vợ chồng sư phụ; năm sư huynh đệ còn lại đều có động phủ riêng bên ngoài, ít khi đến. Hàn Lập vừa Trúc Cơ thành công được thu chính thức làm môn hạ, xếp thứ tự thành Bát sư đệ.","nguon":["@c0238"]},{"id":"phong-gia","name":"Phong gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"chưa rõ","nhanVatChinh":["Tiểu tử Phong gia"],"blurb":"Gia tộc được nhắc trong lời đồn liên quan Đổng Huyên Nhi. Hồng Phất vốn hận ghét Phong gia nên càng phản đối khi nghe nàng có quan hệ với tiểu tử của gia tộc này.","detail":"Phong gia chưa trực tiếp xuất hiện trong chương, nhưng được nhắc như một gia tộc có hiềm khích với Hồng Phất. Lời đồn Đổng Huyên Nhi qua lại với tiểu tử Phong gia là một nguyên nhân khiến Hồng Phất tiếp tục giam nàng.","nguon":["@c0245"]},{"id":"nhom-luc-bao-toc-vang-mat-xam","name":"Nhóm lục bào tóc vàng mắt xám","cn":"","type":"nhom-tu-si","typeLabel":"Nhóm tu sĩ","diaBan":"Yến Linh bảo","nhanVatChinh":["Quái nhân lục bào tóc vàng mắt xám"],"blurb":"Nhóm lục bào tóc vàng mắt xám là nhóm tu sĩ tự tìm tới Yến Linh bảo mà không theo đường khách mời thông thường. Họ đánh bị thương đệ tử tiếp khách, đưa ra thư tín vật khiến trưởng lão Yến gia phải tiếp nhận và yêu cầu tham gia Đoạt bảo đại hội.","detail":"Nhóm này xuất hiện trong biến cố trước lúc Hàn Lập vào Yến Linh bảo. Họ không chỉ gây thương tích cho Tiểu thập lục và Tiểu thập ngũ, mà còn đưa thư cùng tín vật làm các trưởng lão Yến gia phải nén giận mời vào bảo, sau đó mở mười trận tỷ thí Trúc Cơ kỳ với Yến gia; khi Yến Vũ rời đi đón khách, Yến gia đã ở thế hạ phong.","nguon":["@c0247"]},{"id":"dien-vu-duong","name":"Diễn Vũ đường","cn":"","type":"bo-phan","typeLabel":"Bộ phận Yến gia","diaBan":"Yến Linh bảo","nhanVatChinh":["Đường huynh của Yến Vũ"],"blurb":"Bộ phận tập trung đệ tử tinh nhuệ của Yến gia. Các đệ tử nơi đây tu luyện bí pháp và được gọi tới ứng phó nhóm khiêu chiến.","detail":"Yến Linh cho biết các trưởng lão Yến gia đã gọi người đứng đầu đệ tử Diễn Vũ đường tới sau khi nhóm khách lạ liên tục làm đệ tử giao thủ trọng thương. Đường huynh của Yến Vũ thuộc nhóm tinh nhuệ này và được đánh giá có đạo pháp tinh thâm.","nguon":["@c0248"]},{"id":"ma-dao","name":"Ma đạo","cn":"","type":"phe-phai","typeLabel":"Phe pháp hệ","diaBan":"không rõ","nhanVatChinh":["Người áo bào màu lục"],"blurb":"Phe pháp hệ được nhắc qua các thủ đoạn âm hiểm trong tỷ thí tại Yến Linh bảo. Nhóm khiêu chiến bị mô tả là tinh thông pháp thuật và độc thuật ma đạo.","detail":"Trong chương này, ma đạo không xuất hiện như một tông môn cụ thể mà là hệ thủ đoạn của nhóm người khiêu chiến Yến gia. Pháp thuật và độc thuật của họ khiến đệ tử thua trận hôn mê, trúng độc mơ hồ và khó chữa trị.","nguon":["@c0248","@c0311"]},{"id":"quy-linh-mon","name":"Quỷ linh môn","cn":"","aliases":["Quỷ linh môn","Quỷ Linh môn"],"type":"tong-mon","typeLabel":"tông môn ma đạo","diaBan":"không rõ","nhanVatChinh":["Thiếu môn chủ Quỷ linh môn đeo mặt nạ quỷ bạc","Quái nhân lục bào tóc vàng mắt xám","Vương Thiền"],"blurb":"Thế lực đối đầu Yến gia trong cuộc tỷ thí tại Yến linh bảo. Ở chương này, Quỷ linh môn thắng thêm một trận nhờ lục bào quái nhân và chủ động hoãn tỷ thí để chờ Sinh tử đường Yến gia.","detail":"Quỷ linh môn cử lục bào quái nhân giao đấu với Đường huynh Yến gia, dùng Huyền pháp Quỷ linh môn phá Hóa cốt phiến và giành thắng lợi. Sau khi Yến gia năm trận thua bốn, Thiếu môn chủ đeo mặt nạ quỷ bạc đại diện Quỷ linh môn đề nghị tạm dừng các trận còn lại cho đến khi đệ tử Sinh tử đường Yến gia tới.","nguon":["@c0249","@c0272","@c0359"],"tabs":{"tienTrinh":[{"chuong":"@c0359","loai":"mở rộng/mất địa bàn","importance":"normal","giaiDoan":"Chiếm mỏ linh thạch","trangThaiMoc":"cùng Hợp Hoan tông chiếm giữ mỏ linh thạch","text":"Đệ tử Quỷ Linh môn cùng Hợp Hoan tông chiếm cứ mỏ linh thạch có liên quan tới Truyền Tống trận cổ.","anchor":"đây là tu sĩ Quỷ Linh môn cùng Hợp Hoan phái"}]},"trangThai":"đang hoạt động trong vùng Ma đạo chiếm giữ","thanhVien":[{"ten":"Vương Thiền","chucVu":"thiếu chủ","tuChuong":"@c0359","trangThai":"đang hoạt động"}]},{"id":"sinh-tu-duong-yen-gia","name":"Sinh tử đường Yến gia","cn":"","type":"duong-khau","typeLabel":"đường khẩu gia tộc","diaBan":"Yến gia","nhanVatChinh":[],"blurb":"Đường khẩu của Yến gia được Thiếu môn chủ Quỷ linh môn đặc biệt nhắc tới khi đề nghị hoãn tỷ thí. Các đệ tử Sinh tử đường gắn với danh xưng Huyết tu sĩ Yến gia.","detail":"Sinh tử đường Yến gia chưa trực tiếp xuất hiện trong trận này, nhưng được phía Quỷ linh môn xem là đối tượng đáng chờ đợi. Thiếu môn chủ Quỷ linh môn muốn đợi đệ tử Sinh tử đường tới rồi mới tiếp tục năm trận còn lại, cho thấy đường khẩu này giữ vai trò quan trọng trong phần tỷ thí kế tiếp.","nguon":["@c0249"]},{"id":"huyet-tu-si-yen-gia","name":"Huyết tu sĩ Yến gia","cn":"","type":"nhom","typeLabel":"nhóm tu sĩ biệt xưng","diaBan":"Yến gia","nhanVatChinh":[],"blurb":"Danh xưng gắn với đệ tử Sinh tử đường Yến gia, được Thiếu môn chủ Quỷ linh môn nói đã nghe đại danh. Nhóm này được nhắm tới trong các trận tỷ thí tiếp theo.","detail":"Huyết tu sĩ Yến gia được nhắc khi Thiếu môn chủ Quỷ linh môn đề nghị hoãn tỷ thí cho đến lúc đệ tử Sinh tử đường tới. Lời nhắc này cho thấy Quỷ linh môn không chỉ muốn thắng các trận trước mắt mà còn đặc biệt chờ nhóm tinh nhuệ của Yến gia xuất chiến.","nguon":["@c0249"]},{"id":"mac-phu","name":"Mặc phủ","cn":"","type":"gia-toc","typeLabel":"Gia tộc / phủ đệ","diaBan":"Mặc phủ cũ","nhanVatChinh":["Mặc đại phu","Nghiêm thị","Mặc Thải Hoàn","Mặc Ngọc Châu","Lý thị","Vương thị"],"blurb":"Mặc phủ là thế lực cố nhân gắn với tuyến Mặc đại phu và Mặc Thải Hoàn. Đến chương này, Mặc Thải Hoàn tiết lộ Mặc phủ đã bị phá hủy từ bảy năm trước.","detail":"Mặc phủ từng là nơi quy tụ gia quyến và hậu nhân của Mặc đại phu, có liên hệ sâu với quá khứ của Hàn Lập. Biến cố bảy năm trước khiến phủ bị phá hủy, Nhị nương và Ngũ nương chết, Mặc Thải Hoàn cùng Nghiêm thị vất vả chạy thoát và lưu lạc tới Yến linh bảo.","nguon":["@c0250"]},{"id":"ngu-sac-mon","name":"Ngũ sắc môn","cn":"","aliases":[],"type":"giang-ho","typeLabel":"Thế lực giang hồ","diaBan":"Lam châu","nhanVatChinh":[],"blurb":"Ngũ sắc môn là một bá chủ tại Lam châu, có thực lực vượt xa bề ngoài. Sau cái chết của Âu Dương Phi Thiên, thế lực này đánh bại Kinh Giao hội và khiến Mặc phủ lâm vào cảnh tan rã.","detail":"Trong lời kể của Nghiêm thị, Ngũ sắc môn phản ứng rất nhanh sau khi Độc phách sơn trang suy sụp. Kinh Giao hội tưởng chiếm được lợi lớn nhưng đánh giá sai thực lực của Ngũ sắc môn, cuối cùng đại bại; Mặc phủ cũng bị cao thủ của thế lực này tập kích, khiến Lý thị và Vương thị chết khi phá vây.","nguon":["@c0251"]},{"id":"doc-phach-son-trang","name":"Độc phách sơn trang","cn":"","aliases":[],"type":"giang-ho","typeLabel":"Thế lực giang hồ","diaBan":"Lam châu","nhanVatChinh":["Âu Dương Phi Thiên"],"blurb":"Độc phách sơn trang là thế lực gắn với Âu Dương Phi Thiên tại Lam châu. Sự suy sụp của thế lực này mở đầu cho cuộc tranh đoạt giữa Kinh Giao hội và Ngũ sắc môn.","detail":"Sau khi Âu Dương Phi Thiên bị trừ, Độc phách sơn trang không còn giữ được thế cũ. Khoảng trống lợi ích tại Lam châu khiến Kinh Giao hội và Ngũ sắc môn tranh đoạt, cuối cùng dẫn đến Kinh Giao hội bị nhổ tận gốc và Mặc phủ tan rã.","nguon":["@c0251"]},{"id":"yen-linh-bao-the-luc","name":"Yến linh bảo","cn":"","aliases":["Yến gia bảo"],"type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Yến linh bảo","nhanVatChinh":["Yến Trụ","Nghiêm thị","Mặc Thải Hoàn"],"blurb":"Yến linh bảo là nơi Yến Trụ đưa Nghiêm thị và Mặc Thải Hoàn vào cư trú sau khi cứu họ khỏi truy sát. Hai mẹ con về sau sinh sống trong bảo bằng một tiểu điếm nhỏ.","detail":"Nghiêm thị và Mặc Thải Hoàn được Yến Trụ đưa vào Yến linh bảo dưới thân phận người thường di cư. Sau khi Yến Trụ chết khi làm nhiệm vụ gia tộc, mẹ con họ không thể rời bảo, phải dựa vào tiểu điếm để kiếm linh thạch mua thuốc và duy trì sinh kế.","nguon":["@c0251"]},{"id":"ma-dao-luc-tong-thien-la-quoc","name":"Ma đạo lục tông Thiên La quốc","cn":"","aliases":["Sáu tông phái ma đạo của Thiên La quốc","Ma đạo lục tông","lục đại tông phái ma đạo"],"type":"tong-mon","typeLabel":"Cụm thế lực ma đạo","diaBan":"Thiên La quốc","nhanVatChinh":["Vô Du Tử","Hàn Lập"],"blurb":"Cụm sáu tông phái ma đạo lớn của Thiên La quốc, trong đó có Quỷ Linh Môn. Sức mạnh của họ khiến nhóm thất đại phái Việt quốc lo ngại khi Quỷ Linh Môn xuất hiện ở Yến gia.","detail":"Vô Du Tử cho biết Quỷ Linh Môn là một trong sáu tông phái ma đạo của Thiên La quốc; dù là phái yếu nhất, Quỷ Linh Môn vẫn mạnh hơn Yểm Nguyệt tông ba phần. Hàn Lập từng cân nhắc khả năng các ma tông này xâm lấn Việt quốc nhưng tạm loại trừ tình huống xấu nhất vì còn Khương quốc, Xa Kỵ quốc và Chính đạo liên minh xen giữa.","nguon":["@c0253"]},{"id":"chinh-dao-lien-minh","name":"Chính đạo liên minh","cn":"","type":"lien-minh","typeLabel":"Liên minh chính đạo","diaBan":"Khu vực lân cận Thiên La quốc và Việt quốc","nhanVatChinh":["Hàn Lập"],"blurb":"Thế lực được Hàn Lập nhắc tới trong suy luận về khả năng ma đạo Thiên La quốc bành trướng về phía Việt quốc.","detail":"Trong khi cân nhắc giả thuyết ma đạo Thiên La quốc xâm lấn Việt quốc, Hàn Lập cho rằng sự tồn tại của Chính đạo liên minh là một yếu tố khiến ma đạo khó âm thầm khuếch trương lực lượng qua các nước ở giữa.","nguon":["@c0253"]},{"id":"nam-ma-dao-tong-con-lai","name":"Năm ma đạo tông còn lại","cn":"","type":"tong-mon","typeLabel":"Tông môn ma đạo","diaBan":"","nhanVatChinh":[],"blurb":"Các tông ma đạo còn lại được Hàn Lập đặt vào giả thiết có thể liên thủ với Quỷ linh môn. Chương chưa xác nhận việc liên thủ này.","detail":"Khi suy xét biến cố Quỷ linh môn xuất hiện tại Yến gia, Hàn Lập cân nhắc khả năng Quỷ linh môn hành động riêng hoặc có liên quan tới các ma đạo tông khác. Vai trò cụ thể của năm tông này trong sự việc chưa được hé lộ.","nguon":["@c0254"]},{"id":"thien-tinh-tong-phuong-thi","name":"Thiên tinh tông phường thị","cn":"","type":"phuong-thi","typeLabel":"Phường thị liên quan tông môn","diaBan":"không rõ","nhanVatChinh":["Hàn Lập"],"blurb":"Phường thị được Hàn Lập nhắc cùng Hoàng Phong cốc trong việc tìm nguyên liệu luyện đan. Những tài liệu hắn cần không dễ tìm thấy ở nơi này.","detail":"Thiên tinh tông phường thị được nhắc trong mạch Hàn Lập tìm nguyên liệu luyện đan. Việc hắn không tìm đủ nguyên liệu ở đây làm nổi bật giá trị của hội trao đổi tại Yến linh bảo.","nguon":["@c0255"]},{"id":"chinh-dao-lien-minh-phong-do-quoc","name":"Chính đạo liên minh Phong Đô quốc","cn":"","type":"lien-minh","typeLabel":"Liên minh chính đạo","diaBan":"Phong Đô quốc","nhanVatChinh":[],"blurb":"Chính đạo liên minh Phong Đô quốc là thế lực chính đạo được Yến gia lão tổ nhắc tới khi bàn thế cục. Họ cũng đang xâm lấn một quốc gia bậc trung lân cận, nên không thể trở thành chỗ dựa cho Yến gia trước ma đạo.","detail":"Trong cuộc nghị sự, Yến gia lão tổ bác bỏ khả năng trông chờ Chính đạo liên minh đối phó ma đạo. Việc liên minh này cũng khuếch trương khiến Huyền Dạ chú ý đến khả năng chính-ma đồng thời mở rộng thế lực ở Thiên Nam.","nguon":["@c0256"]},{"id":"bay-dai-mon-phai","name":"Bảy đại môn phái","cn":"","type":"tong-mon-lien-minh","typeLabel":"Liên minh môn phái","diaBan":"Việt quốc","nhanVatChinh":["Hàn Lập","Đổng Huyên Nhi","Phong sư huynh"],"blurb":"Các môn phái chính đạo tại Việt quốc có đệ tử Trúc Cơ đang ở Yến gia bảo trong thời điểm Yến gia chuẩn bị quy phụ Quỷ Linh môn.","detail":"Yến gia lo bảy đại môn phái phát hiện việc di dời nên phải che giấu hành tung. Trong cuộc thương lượng với Vương Thiền, Yến gia đồng ý gom riêng đệ tử bảy phái lại để Quỷ Linh môn tự bắt hoặc xử trí, nhằm giữ đường giải thích cho gia tộc.","nguon":["@c0257"]},{"id":"chap-phap-doi-bay-dai-phai","name":"Chấp pháp đội bảy đại phái","cn":"","type":"luc-luong","typeLabel":"Lực lượng chấp pháp","diaBan":"Việt quốc","nhanVatChinh":[],"blurb":"Lực lượng được nhắc trong thư lệnh chung của bảy đại phái Việt quốc. Các gia tộc không giao đệ tử kiệt xuất theo lệnh sẽ bị Chấp pháp đội diệt tộc.","detail":"Khi bảy đại phái động viên toàn Việt quốc, thư lệnh gửi các gia tộc nêu rõ yêu cầu đưa đệ tử kiệt xuất đến chờ lệnh. Gia tộc nào trái lệnh sẽ bị Chấp pháp đội của bảy đại phái xử lý bằng cách diệt tộc.","nguon":["@c0259"]},{"id":"quy-linh-thap-nhi-ve","name":"Quỷ Linh thập nhị vệ","cn":"","type":"luc-luong","typeLabel":"Lực lượng Quỷ Linh môn","diaBan":"Yến Linh Bảo","nhanVatChinh":["Vương Thiền","Số tám trong Quỷ Linh thập nhị vệ","Số mười hai trong Quỷ Linh thập nhị vệ"],"blurb":"Lực lượng dưới quyền Vương Thiền, được chuẩn bị để xử lý những tu sĩ thoát khỏi Âm Hỏa đại trận. Số tám và số mười hai trong lực lượng này được lệnh truy sát hai tu sĩ vắng mặt.","detail":"Trong kế hoạch phục kích tại núi phía tây Yến Linh Bảo, Vương Thiền tin Quỷ Linh thập nhị vệ đủ sức xử lý cá lọt lưới sau khi Âm Hỏa đại trận phát huy tác dụng. Khi phát hiện còn thiếu hai tu sĩ, hắn phái số tám và số mười hai đi đuổi giết để không ai sống sót rời khỏi Yến Linh Bảo.","nguon":["@c0259"]},{"id":"hop-hoan-tong","name":"Hợp Hoan Tông","cn":"","aliases":["Hợp Hoan phái"],"type":"tong-mon","typeLabel":"Tông môn","diaBan":"không rõ","nhanVatChinh":["Điền Bất Khuyết"],"blurb":"Hợp Hoan Tông là một tông thuộc Ma Đạo Lục Tông. Trong chương này, nhóm của Điền Bất Khuyết tập kích lực lượng Quỷ Linh Môn và cướp hai nữ tu sĩ bị chế phục.","detail":"Cuộc tập kích của Hợp Hoan Tông không gây thương vong cho Quỷ Linh Môn nhưng cướp được hai nữ tu sĩ, khiến Vương Thiền giận dữ và đưa Điền Bất Khuyết vào danh sách phải giết. Sự kiện cho thấy mâu thuẫn ngầm giữa các phe trong Ma Đạo Lục Tông.","nguon":["@c0262","@c0297","@c0339"],"tabs":{"tienTrinh":[{"chuong":"@c0339","loai":"nhắc tới","importance":"normal","giaiDoan":"Quan hệ cũ với Yểm Nguyệt tông","text":"Hợp Hoan tông được nhắc là tông môn từng có liên hệ sâu xa với Yểm Nguyệt tông, nhưng quan hệ ấy đã bị đoạn tuyệt từ lâu.","trangThaiMoc":"Từng liên hệ với Yểm Nguyệt tông","anchor":"mấy trăm năm trước liền đoạn tuyệt liên hệ với Hợp Hoan tông"}]},"trangThai":"đang hoạt động"},{"id":"yen-gia","name":"Yến Gia","cn":"","type":"gia tộc","typeLabel":"Gia tộc tu tiên","diaBan":"Yến Linh Bảo","nhanVatChinh":[],"blurb":"Gia tộc tu tiên tại Yến Linh Bảo bị Hàn Lập báo tin là đã cấu kết với Ma Đạo.","detail":"Trong chương này, Hàn Lập thuật lại biến cố Yến Linh Bảo cho Tuyên Nhạc, khiến đội chi viện biết chuyện Yến Gia có liên hệ Ma Đạo. Do thực lực không đủ, nhóm Tuyên Nhạc chỉ chuyển tin cho các phái chứ không trực tiếp hỏi tội hay cứu người.","nguon":["@c0263"]},{"id":"ngu-linh-tong","name":"Ngự Linh Tông","cn":"","type":"tong-mon","typeLabel":"Tông môn Ma Đạo","diaBan":"Thiên Nam","nhanVatChinh":["Tu sĩ Ngự Linh Tông"],"blurb":"Ngự Linh Tông là bản tông Ma Đạo từng cài Linh Thú Sơn làm phân nhánh ở Việt Quốc. Sau mấy nghìn năm, Linh Thú Sơn không còn muốn quy phục khiến kế hoạch của Ma Đạo bị đảo ngược.","detail":"Chiến cuộc tiết lộ Linh Thú Sơn trong thất phái vốn là phân nhánh của Ma Đạo Ngự Linh Tông. Tuy nhiên thời gian quá lâu khiến tầng lớp cầm quyền Linh Thú Sơn không muốn nhận mình thuộc Ngự Linh Tông nữa, rồi phối hợp với lục phái còn lại lừa Ma Đạo vào thế bị phục kích.","nguon":["@c0265","@c0272","@c0339"],"tabs":{"tienTrinh":[{"chuong":"@c0339","loai":"nhắc tới","importance":"major","giaiDoan":"Lộ quan hệ ngầm","text":"Tu sĩ trong thân Khúc Hồn tiết lộ Linh Thú Sơn từ khi lập tông vẫn bí mật liên hệ với Ngự Linh tông, làm lộ tầng quan hệ ngầm giữa tông môn Việt Quốc và ma đạo Thiên Đô quốc.","trangThaiMoc":"Lộ quan hệ ngầm với Linh Thú Sơn","anchor":"Linh Thú sơn từ khi lập tông đến giờ, vẫn không ngừng bí mật liên hệ với Ngự Linh tông chúng ta"}]},"trangThai":"đang hoạt động","thanhVien":[{"ten":"Tu sĩ Ngự Linh Tông","chucVu":"Tu sĩ trong tông","tuChuong":"@c0339","trangThai":"còn sống, đang chiếm thân Khúc Hồn"}]},{"id":"yem-nguyet-mon","name":"Yểm Nguyệt Môn","cn":"","type":"tong-mon","typeLabel":"Tông môn thuộc thất phái","diaBan":"Việt Quốc","nhanVatChinh":["Tuyên Nhạc"],"blurb":"Yểm Nguyệt Môn là một tông môn thuộc phe thất phái Việt Quốc. Tuyên Nhạc của môn phái này tham gia trấn thủ linh khoáng Đại Hiệp Cốc khi Ma Đạo tập kích.","detail":"Trong phòng tuyến linh khoáng Đại Hiệp Cốc, Tuyên Nhạc của Yểm Nguyệt Môn cùng Lỗ Thiên Mông của Linh Thú Sơn đứng dưới Tứ Sát Trận quan sát địch nhân Ma Đạo phía trên cốc.","nguon":["@c0265"]},{"id":"tu-kim-quoc-tu-tien-gioi","name":"Tử Kim Quốc tu tiên giới","cn":"","type":"lien-minh","typeLabel":"Tu tiên giới quốc gia","diaBan":"Tử Kim Quốc","nhanVatChinh":[],"blurb":"Tử Kim Quốc tu tiên giới cùng Nguyên Vũ Quốc đưa lực lượng đến hỗ trợ Việt Quốc. Họ tham chiến vì lo Ma Đạo nuốt trọn Việt Quốc rồi tiếp tục mở rộng.","detail":"Tu sĩ Tử Kim Quốc là một phần viện quân các nước lân cận Việt Quốc. Sự có mặt của họ giúp cân bằng lực lượng giữa Ma Đạo lục tông và phe chống Ma Đạo, kéo chiến tranh vào cục diện giằng co.","nguon":["@c0265"]},{"id":"tu-tien-gioi-khuong-quoc","name":"Tu tiên giới Khương Quốc","cn":"","type":"lien-minh","typeLabel":"Tu tiên giới quốc gia","diaBan":"Khương Quốc","nhanVatChinh":[],"blurb":"Tu tiên giới Khương Quốc được nhắc trong bối cảnh Ma Đạo từng nắm được nước này. Ranh giới Việt Quốc với Khương Quốc trở thành một trong các khu vực giao chiến dữ dội.","detail":"Trong đại chiến, song phương liên tục đánh ở ranh giới Việt Quốc với Khương Quốc và Xa Kỵ Quốc. Khương Quốc là một nền địa chính trị quan trọng cho thế xâm nhập của Ma Đạo lục tông.","nguon":["@c0265"]},{"id":"tu-tien-gioi-xa-ky-quoc","name":"Tu tiên giới Xa Kỵ Quốc","cn":"","type":"lien-minh","typeLabel":"Tu tiên giới quốc gia","diaBan":"Xa Kỵ Quốc","nhanVatChinh":[],"blurb":"Tu tiên giới Xa Kỵ Quốc được nhắc cùng Khương Quốc trong bối cảnh chiến trường ranh giới với Việt Quốc. Đây là khu vực từng chịu ảnh hưởng từ thế tiến của Ma Đạo.","detail":"Ma Đạo lục tông từng thành công ở khu vực Khương Quốc và Xa Kỵ Quốc, rồi tiếp tục đưa chiến sự tới ranh giới Việt Quốc. Các trận đại chiến liên tiếp tại vùng này gây thương vong cực lớn cho hai bên.","nguon":["@c0265"]},{"id":"ma-diem-mon","name":"Ma Diễm môn","cn":"","type":"tong-mon","typeLabel":"Tông môn ma đạo","diaBan":"Thiên La quốc","nhanVatChinh":["Hồng y nữ tử","Hồng y nhân Ma Diễm môn / Cuồng diễm tu sĩ","Bóng trắng ẩn thân trước Ma Diễm môn"],"blurb":"Ma Diễm môn là một trong các tông phái ma đạo xuất hiện tại chiến trường linh quáng. Đội hồng y nhân của môn này bày trận dùng đại kỳ đỏ rực để phóng Thanh dương ma hỏa.","detail":"Trong trận công kích linh quáng, Ma Diễm môn phối hợp với Thiên Sát tông. Nhóm hồng y nhân không lao vào giao chiến ngay mà lập trận hình kỳ quái, được bóng trắng ẩn thân bảo vệ để hoàn tất Thanh dương ma hỏa, tạo thế nguy cho thất phái.","nguon":["@c0266"]},{"id":"thien-sat-tong","name":"Thiên Sát tông","cn":"","type":"tong-mon","typeLabel":"Tông môn ma đạo","diaBan":"Thiên La quốc","nhanVatChinh":["Hoàng sam lão giả","Mười hoàng y tu sĩ Thiên Sát tông","Tu sĩ trung niên Thiên Sát tông"],"blurb":"Thiên Sát tông là một trong các tông phái ma đạo tham chiến tại linh quáng. Đội hoàng y tu sĩ của tông này mở màn bằng việc dùng pháp khí oanh kích tứ sát trận.","detail":"Dưới lệnh của hoàng sam lão giả, mười tu sĩ áo vàng Thiên Sát tông hóa thành hoàng quang đánh úp bốn sát trận, nhưng dừng ngoài hơn mười trượng để phá trận bằng pháp khí. Một tu sĩ trung niên của tông này trực tiếp giao thủ với Hàn Lập bằng Thanh qua và viên châu trắng.","nguon":["@c0266"]},{"id":"ma-dao-nhi-tong","name":"Ma đạo nhị tông","cn":"","type":"lien-minh","typeLabel":"Liên quân hai tông ma đạo","diaBan":"","nhanVatChinh":["Liên Phi Hoa","Hoàng sam lão giả"],"blurb":"Liên quân hai tông ma đạo tham gia phá hủy linh quáng rồi rời khỏi khu vực. Đây là một bộ phận trong chiến dịch rộng hơn của ma đạo nhằm vào thất đại phái.","detail":"Sau khi linh quáng bị phá hủy sạch, nhóm người của hai tông ma đạo rút đi. Sự kiện này nối tiếp bằng việc dược viên bí mật của thất đại phái bị tập kích, khiến xung đột giữa hai phe leo thang.","nguon":["@c0268"]},{"id":"bay-phai-viet-quoc","name":"Bảy phái Việt quốc","cn":"","aliases":["Thất phái"],"type":"lien-minh","typeLabel":"Liên minh chính đạo","diaBan":"Việt quốc","nhanVatChinh":["Hàn Lập"],"blurb":"Liên minh các phái tu tiên Việt quốc đang giao chiến với sáu tông ma đạo. Trong đợt đại chiến thứ hai, bảy phái nhờ hai nước trợ giúp nên tạm chiếm thượng phong.","detail":"Bảy phái Việt quốc bước vào đợt đại chiến thứ hai với sáu tông ma đạo và nhờ trợ lực từ hai nước nên tạm thời chiếm ưu thế. Trong bối cảnh thời chiến, phe này xử phạt nghiêm khắc những đệ tử trốn tránh nhiệm vụ hoặc lẩn sang nước khác, khiến Hàn Lập càng muốn tìm đường rời khỏi vũng nước đục chiến tranh.","nguon":["@c0271"]},{"id":"sau-tong-ma-dao","name":"Sáu tông ma đạo","cn":"","aliases":["Lục tông","Ma đạo lục tông","lục đạo"],"type":"lien-minh","typeLabel":"Liên minh ma đạo","diaBan":"không rõ","nhanVatChinh":[],"blurb":"Phe đối địch với bảy phái Việt quốc trong chiến sự chính ma. Chiến cuộc với sáu tông là nguyên nhân khiến Hàn Lập muốn sửa Cổ Truyền tống trận để tránh xa.","detail":"Sáu tông ma đạo là lực lượng giao chiến với bảy phái Việt quốc. Chương này cho thấy đợt đại chiến thứ hai đã bắt đầu, và chính sự giằng co với phe này khiến Hàn Lập xem Cổ Truyền tống trận như một con đường rời khỏi cuộc chiến.","nguon":["@c0271"]},{"id":"phe-ma-dao","name":"Phê Ma đạo","cn":"","aliases":[],"type":"nhom","typeLabel":"Nhóm ma đạo được nhắc","diaBan":"không rõ","nhanVatChinh":[],"blurb":"Nhóm ma đạo được Hàn Lập lo ngại có thể còn lảng vảng gần lối ra. Nỗi lo này khiến hắn rời địa đạo rất thận trọng.","detail":"Khi thoát khỏi địa đạo, Hàn Lập không dám trì hoãn vì lo sợ người Phê Ma đạo còn quanh quẩn gần lối ra. Chương này chỉ nêu nhóm này trong bối cảnh nguy hiểm sau khi hắn rời huyệt động.","nguon":["@c0271"]},{"id":"truc-co-that-phai","name":"Trúc Cơ thất phái","cn":"","type":"lien-minh","typeLabel":"Liên minh tu sĩ Trúc Cơ","diaBan":"chiến trường giữa thất phái và ma đạo","nhanVatChinh":["Hàn Lập"],"blurb":"Trúc Cơ thất phái chỉ tầng tu sĩ Trúc Cơ thuộc bảy phái Việt quốc đang tham chiến. Trong phạm vi này, Hàn Lập bắt đầu có danh khí nhờ liên tiếp giết tu sĩ ma đạo.","detail":"Ở chương 273, thành tích một năm của Hàn Lập được lan truyền trong giới tu sĩ Trúc Cơ của thất phái. Danh tiếng này khiến người khác nhìn hắn như người mới nổi bật của Hoàng Phong cốc, dù tu vi chỉ là Trúc Cơ trung kỳ.","nguon":["@c0273"]},{"id":"tran-thi","name":"Trần thị","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"không rõ","nhanVatChinh":["Trần mập","Trần sư muội"],"blurb":"Trần thị là gia tộc tu tiên của Trần mập và Trần sư muội. Trần mập có ý định tiến cử Hàn Lập với gia chủ sau chiến sự để lung lạc làm trợ thủ.","detail":"Chương 273 xác nhận Trần mập là Ngũ bá của Trần sư muội và có thể hướng gia chủ tiến cử nhân tài. Việc ông muốn đưa Hàn Lập vào tầm mắt Trần thị cho thấy gia tộc này đang tìm kiếm trợ lực sau chiến sự.","nguon":["@c0273"]},{"id":"luc-ba-dong","name":"Lục Ba động","cn":"","type":"khac","typeLabel":"Trú địa môn hạ","diaBan":"Hoàng Phong Cốc","nhanVatChinh":["Lý Hóa Nguyên","Phu nhân Lý Hóa Nguyên","Tống Mông"],"blurb":"Nơi Tống Mông từ nhỏ sinh sống dưới môn hạ Lý Hóa Nguyên. Vì sống ở đây lâu năm, Tống Mông bị nhận xét thiếu lịch lãm thế tục nên không được chọn đi bảo vệ gia đình phàm nhân.","detail":"Lục Ba động được nhắc như môi trường sinh hoạt của Tống Mông. Phu nhân Lý Hóa Nguyên dùng điểm này để giải thích vì sao Tống Mông không thích hợp làm hộ vệ cho một gia đình phàm tục trong thế tục Việt quốc.","nguon":["@c0274"]},{"id":"hoang-that-viet-quoc","name":"Hoàng thất Việt quốc","cn":"","type":"hoang-that","typeLabel":"Hoàng thất","diaBan":"Bắc khu Việt Kinh","nhanVatChinh":[],"blurb":"Hoàng thất cư trú trong hoàng thành thuộc Bắc khu Việt Kinh.","detail":"Bắc khu của Việt Kinh là hoàng thành, người ngoài hoàng thất không được cư ngụ trong khu vực này.","nguon":["@c0278"]},{"id":"quan-lai-viet-quoc","name":"Quan lại Việt quốc","cn":"","type":"trieu-dinh","typeLabel":"Quan lại triều đình","diaBan":"Nam khu Việt Kinh","nhanVatChinh":[],"blurb":"Tầng lớp quan lại lớn nhỏ cư trú tại Nam khu Việt Kinh.","detail":"Nam khu của Việt Kinh là nơi dành cho các quan lại trong triều. Gia đình nào không còn người giữ chức quan thì phải rời khỏi khu này.","nguon":["@c0278"]},{"id":"trieu-dinh-viet-quoc","name":"Triều đình Việt quốc","cn":"","type":"the-tuc","typeLabel":"Thế lực thế tục","diaBan":"Việt quốc","nhanVatChinh":[],"blurb":"Triều đình Việt quốc được nhắc qua quan hệ chống lưng cho Tần gia. Sự hiện diện của quan to trong triều giúp thế lực tài phú Tần gia thêm vững chắc.","detail":"Trong chương, Tần gia có quan to trong triều đứng ra nói chuyện, khiến một đại phú gia thương mại có thêm chỗ dựa thế tục. Chi tiết này giải thích vì sao hạ nhân Tần trạch cũng kiêu căng hơn người thường.","nguon":["@c0279"]},{"id":"tan-phu-the-luc","name":"Tần phủ","cn":"","type":"gia-toc","typeLabel":"Thế lực phàm tục","diaBan":"Việt Kinh","nhanVatChinh":["Tần Bình","Tần Ngôn","Hàn Lập"],"blurb":"Tần phủ là gia tộc phàm tục có danh tiếng lớn trong kinh thành. Khi Tần Bình nhắc Hàn Lập là thiếu gia Tần phủ, điếm tiểu nhị lập tức tỏ ra đặc biệt cung kính.","detail":"Trong lần Hàn Lập cùng Tần Bình vào tửu lâu, danh tiếng Tần phủ đủ khiến người phục vụ nhanh chóng đổi thái độ. Điều này cho thấy Tần phủ có địa vị đáng kể trong đời sống phàm tục ở kinh thành.","nguon":["@c0284"]},{"id":"mong-son-ngu-huu","name":"Mông Sơn Ngũ Hữu","cn":"","type":"nhom-tan-tu","typeLabel":"Nhóm tán tu","diaBan":"Việt Quốc","nhanVatChinh":["Đại ca Mông Sơn ngũ hữu","Lam y nhân Mông Sơn Ngũ Hữu","Nữ nhân áo trắng Mông Sơn Ngũ Hữu","Hán tử cao gầy Mông Sơn Ngũ Hữu","Nam nhân hơn bốn mươi tuổi Mông Sơn Ngũ Hữu","Nữ nhân hơn bốn mươi tuổi Mông Sơn Ngũ Hữu"],"blurb":"Mông Sơn Ngũ Hữu là nhóm năm tán tu Luyện Khí kỳ gồm ba nam hai nữ. Trong chương này, nhóm lộ ra việc đã bị kẻ bí ẩn gieo cấm chế và nắm sinh tử.","detail":"Nhóm bị ép cân nhắc làm theo sắp đặt của kẻ khác, trong khi vẫn không muốn hãm hại tu sĩ Việt Quốc. Đại ca của nhóm cho rằng cầu viện Thất đại phái khó hiệu quả vì đối phương có tu sĩ Trúc Cơ kỳ, đeo mặt nạ, không để lộ tung tích và nắm cấm chế trên người họ.","nguon":["@c0284","@c0301"]},{"id":"tan-tu-viet-quoc","name":"Tán tu Việt Quốc","cn":"","type":"cong-dong","typeLabel":"Quần thể tu sĩ","diaBan":"Việt Quốc","nhanVatChinh":["Mông Sơn Ngũ Hữu"],"blurb":"Tán tu Việt Quốc là quần thể tu sĩ không thuộc các đại phái trong Việt Quốc. Lời Mông Sơn Ngũ Hữu cho thấy nhiều đồng đạo đã rơi vào tay một nhóm kẻ xấu bí ẩn.","detail":"Nữ nhân áo trắng nhắc tới việc nhiều đồng đạo Việt Quốc đã bị bắt, còn lão già mặt đen tự nhận nhóm mình chỉ là tán tu khó khiến Thất đại phái dốc lực cứu giúp. Bối cảnh này cho thấy tầng lớp tán tu đang chịu áp lực lớn trong lúc Ma Đạo xâm nhập.","nguon":["@c0284"]},{"id":"hinh-vuong-phu","name":"Hinh Vương phủ","cn":"","type":"vuong-phu","typeLabel":"Vương phủ","diaBan":"Nam khu Việt Kinh","nhanVatChinh":["Hinh Vương","Tổng quản Hinh Vương phủ","Thanh nhi","Tiểu Vương gia"],"blurb":"Hinh Vương phủ là phủ đệ của Hinh Vương tại nam khu Việt Kinh. Nơi này có tổng quản tiếp khách, cấm binh canh cửa và tổ chức buổi tụ họp đông đảo khách quý.","detail":"Trong chương này, Hinh Vương phủ tiếp đón nhiều tân khách mang theo con cháu trẻ tuổi. Phủ đệ có quy mô lớn, cửa bọc đồng vàng, tượng sư tử đồng và mười sáu cấm binh canh giữ, thể hiện địa vị vương tước của chủ nhân.","nguon":["@c0286"]},{"id":"hoang-toc","name":"Hoàng tộc","cn":"","type":"the-tuc","typeLabel":"Thế lực thế tục","diaBan":"Việt Quốc","nhanVatChinh":["Hinh Vương","Tiểu vương gia Minh nhi"],"blurb":"Tầng lớp hoàng tộc thế tục của Việt Quốc. Thân phận này được dùng để nhấn mạnh ngay cả Hinh Vương cũng hiếm khi thấy người tu chân chân chính.","detail":"Hinh Vương là người trong hoàng tộc nhưng vẫn xem việc tận mắt thấy người tu chân và pháp thuật là chuyện hiếm có. Điều đó cho thấy khoảng cách giữa quyền thế phàm tục và tu tiên giới trong giai đoạn này.","nguon":["@c0290"]},{"id":"hoa-gia","name":"Hoa gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc thế tục","diaBan":"Việt Quốc","nhanVatChinh":["Hoa lão ca","Hoa Nam","Hoa Phương"],"blurb":"Gia tộc thế tục có quan hệ thế giao với Tần gia và Hinh Vương phủ. Con cháu Hoa gia cũng được kiểm tra tiên căn trong buổi tiệc nhưng không có kết quả.","detail":"Lão giả họ Hoa dẫn đôi nam nữ thanh niên Hoa gia tham gia kiểm tra tiên duyên tại Hinh Vương phủ. Sau khi không ai có linh căn, ông cùng Tần Ngôn cười khổ và tiếp tục quan sát cục diện trong phủ.","nguon":["@c0290"]},{"id":"gia-toc-tu-tien","name":"Gia tộc tu tiên","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Tu tiên giới","nhanVatChinh":[],"blurb":"Những gia tộc có người tu tiên, được nhắc trong phần giải thích về quan hệ giữa tu tiên giới và thế tục. Một số tu sĩ cấp thấp từ các gia tộc này từng chán nản việc Trúc Cơ và lưu lại thế tục hưởng phú quý.","detail":"Chương nêu rằng trước kia có tán tiên và người tu tiên cấp thấp trong gia tộc tu tiên vì không còn hy vọng Trúc Cơ mà lưu luyến thế tục. Sau khi Thăng Tiên đại hội xuất hiện, nhóm người này cũng bị cuốn vào tranh đoạt cơ hội tu luyện hơn là làm môn khách phàm nhân.","nguon":["@c0290"]},{"id":"tieu-gia-phong-ha-gian","name":"Tiêu gia Phong Hà giản","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Phong Hà giản, Duẫn Châu","nhanVatChinh":["Tiêu Chấn","Thiếu nữ họ Tiêu"],"blurb":"Gia tộc tu tiên mà Tiêu Chấn tự nhận thuộc về khi bị Hàn Lập chất vấn. Hàn Lập chưa tin chắc danh xưng này là thật.","detail":"Tiêu Chấn nói mình là người của Tiêu gia ở Phong Hà giản, Duẫn Châu, vì tuổi cao vô vọng Trúc Cơ nên phụ trách tài chính cho gia tộc. Hàn Lập không nhớ từng nghe tên gia tộc này và nghi ngờ đó có thể chỉ là lời nói tùy tiện.","nguon":["@c0291"]},{"id":"vuong-phu","name":"Vương phủ","cn":"","type":"phu-de","typeLabel":"Phủ đệ phàm tục","diaBan":"Việt Kinh","nhanVatChinh":["Hinh Vương","Vương tổng quản","Tiểu vương gia Minh nhi","Ngô tiên sư"],"blurb":"Phủ đệ nơi Hàn Lập giao nhiệm vụ giám thị cho lão đạo tóc bạc.","detail":"Trong chương này, Vương phủ là nơi lão đạo tóc bạc đang ở và cũng là nơi Hàn Lập rời đi sau khi buộc lão giám thị Vương tổng quản cùng Tiểu vương gia.","nguon":["@c0295"]},{"id":"nhom-ao-den-che-mat","name":"Nhóm áo đen che mặt","cn":"","type":"nhom-bi-mat","typeLabel":"Nhóm hành động bí mật","diaBan":"Ngoại thành Việt Kinh","nhanVatChinh":["Đại ca nhóm áo đen che mặt ở ngoại thành Việt Kinh","Người áo đen dáng thon dài trong nhóm áo đen","Nữ tử áo đen","Người áo đen bộ dáng cao gầy trong nhóm áo đen"],"blurb":"Bốn người che mặt ẩn dưới đất gần ngọn đồi ngoại thành Việt Kinh. Họ nhận lệnh bắt sống hoặc giết Hàn Lập nhưng không dám ra tay khi nhận ra hắn là tu sĩ Trúc Cơ kỳ.","detail":"Nhóm áo đen chờ Hàn Lập rời khỏi hiện trường mới chui lên từ dưới đất trong màn hào quang màu vàng. Họ bàn bạc về nhiệm vụ thất bại, tự bào chữa rằng thông tin ban đầu không nói mục tiêu là Trúc Cơ kỳ, rồi nhanh chóng rời khỏi nơi đó.","nguon":["@c0297"]},{"id":"bon-giao-cua-hai-ke-ao-do","name":"Bổn giáo của hai kẻ áo đỏ","cn":"","type":"bi-an","typeLabel":"Thế lực bí ẩn","diaBan":"chưa rõ","nhanVatChinh":["Lão giả áo đỏ của bổn giáo","Người trẻ tuổi áo đỏ của bổn giáo"],"blurb":"Bổn giáo của hai kẻ áo đỏ là thế lực bí ẩn vừa kết nạp Mông Sơn Ngũ Hữu. Thế lực này có huyết chú cấm chế, bí mật hạ thủ thuộc hạ và triển khai kế hoạch kim thiền thoát xác qua Ngô lão đạo.","detail":"Trong chương 298, hai kẻ áo đỏ cho thấy bổn giáo đã kết nạp Mông Sơn Ngũ Hữu nhưng không hoàn toàn tin dùng họ. Người trẻ tuổi áo đỏ tiết lộ đã hạ thủ nhóm này khiến họ chỉ còn sống được nửa ngày, còn lão giả áo đỏ nói đến kế hoạch dùng Ngô lão đạo làm sư phụ bù nhìn để đệ tử nòng cốt có thân phận khác bên ngoài Tu tiên giới.","nguon":["@c0298"]},{"id":"phe-giao-chu-tai-viet-kinh","name":"Phe giáo chủ tại Việt Kinh","cn":"","type":"the-luc","typeLabel":"Thế lực","diaBan":"Việt Kinh","nhanVatChinh":["Giáo chủ","Tiểu vương gia Minh nhi","Vương tổng quản","Tứ đại Huyết thị"],"blurb":"Thế lực ma đạo đứng sau Tiểu vương gia, Vương tổng quản và Huyết thị tại Việt Kinh. Đang săn bắt tu sĩ để phục vụ việc huyết tế luyện công.","detail":"Thế lực này được hé lộ qua cuộc bàn bạc giữa Tiểu vương gia và Vương tổng quản. Giáo chủ đang cần huyết tế một số tu sĩ Trúc Cơ kỳ để luyện công, nên Vương tổng quản muốn xin điều Huyết thị bắt sống người đã cứu Mông sơn ngũ hữu, khiến Hàn Lập trở thành mục tiêu của họ.","nguon":["@c0299"]},{"id":"phe-dung-sau-ha-huyet-chu","name":"Phe đứng sau hạ huyết chú","cn":"","type":"nhom-bi-an","typeLabel":"Nhóm bí ẩn","diaBan":"không rõ","nhanVatChinh":["Người hạ chú","Lão Nhị cao gầy","Lão giả mặt đen","Tứ ca","Nữ tử trẻ tuổi","Tam muội"],"blurb":"Phe bí ẩn đứng sau việc dùng huyết chú khống chế nhóm bốn người và giữ Tam muội làm con tin. Thế lực này chưa lộ danh tính, nhưng đã dùng cấm chế, uy hiếp và nguy cơ tra tấn để ngăn thuộc hạ tiết lộ cơ mật.","detail":"Trong chương 300, nhóm bốn người bị bắt khai rằng họ bị một phe đứng sau hạ huyết chú cấm chế, không thể tiết lộ chuyện trọng yếu cho người ngoài. Phe này còn khống chế Tam muội, đạo lữ đang mang thai của Lão Nhị, khiến Lão Nhị sợ nàng bị tra tấn sống không bằng chết nếu cơ mật bị lộ.","nguon":["@c0300"]},{"id":"the-luc-dung-huyet-chu-khong-che-mong-son-ngu-huu","name":"Thế lực dùng huyết chú khống chế Mông Sơn ngũ hữu","cn":"","type":"the-luc-doi-dich","typeLabel":"Thế lực đối địch","diaBan":"Việt Kinh","nhanVatChinh":["Người phân phó việc cho Mông Sơn ngũ hữu"],"blurb":"Đây là phe chưa lộ tên đứng sau việc khống chế Mông Sơn ngũ hữu bằng huyết chú. Dấu hiệu chén rượu có độc cho thấy họ còn dùng thủ đoạn hạ độc để ép buộc hoặc diệt khẩu người được sai phái.","detail":"Qua lời Hàn Lập và hồi tưởng của lão nhị cao gầy, phe này không chỉ đặt huyết chú lên Mông Sơn ngũ hữu mà còn có khả năng sai người ép nhóm uống rượu độc trước khi xuất phát. Sau khi nhóm được giải chú, lão giả mặt đen dự liệu họ sẽ bị phe này truy sát.","nguon":["@c0301"]},{"id":"that-phai","name":"Thất phái","cn":"","type":"lien-minh","typeLabel":"Tập hợp tông môn","diaBan":"Việt Quốc","nhanVatChinh":["Hàn Lập"],"blurb":"Thất phái là tập hợp các môn phái tu tiên lớn tại Việt Quốc, được Mông Sơn ngũ hữu xem là chỗ dựa mạnh hơn thế lực khống chế họ. Hàn Lập dùng thân phận tu sĩ Hoàng Phong cốc thuộc thất phái để trấn an nhóm.","detail":"Khi cân nhắc điều kiện của Hàn Lập, lão giả mặt đen suy đoán lai lịch của hắn không ngoài phạm vi thất phái. Uy danh này khiến Mông Sơn ngũ hữu chấp nhận đi theo Hàn Lập vì tin rằng ở cạnh tu sĩ thất phái sẽ an toàn hơn sau khi phản lại phe khống chế.","nguon":["@c0301"]},{"id":"hac-sat-giao","name":"Hắc sát giáo","cn":"","aliases":["Hắc sát giáo"],"type":"ta-giao","typeLabel":"Tà giáo","diaBan":"Việt Kinh","nhanVatChinh":[],"blurb":"Hắc sát giáo là thế lực tà giáo đối địch đang hoạt động tại Việt Kinh. Tổ chức này bắt tu tiên giả để luyện tà công và từng dùng huyết chú khống chế Mông Sơn ngũ hữu.","detail":"Mông Sơn ngũ hữu xác nhận phe đã hại họ thuộc tà giáo tên Hắc sát giáo. Tổ chức này có hai kẻ phát hiệu thi lệnh chưa lộ mặt với nhóm, và Hàn Lập dự định bắt sống hai kẻ đó để tra rõ phần lớn nội tình.","nguon":["@c0302"]},{"id":"mong-son-tu-huu","name":"Mông Sơn tứ hữu","cn":"","type":"nhom-tu-si","typeLabel":"Nhóm tu sĩ","diaBan":"Không rõ","nhanVatChinh":["Lão giả mặt đen","Lão Nhị cao gầy","Trung niên nữ tử","Ngũ muội"],"blurb":"Mông Sơn tứ hữu là nhóm bốn tu sĩ Luyện Khí kỳ còn lại của Mông Sơn ngũ hữu, đang đứng cùng Hàn Lập chống Hắc Sát giáo.","detail":"Trong trận với Hắc Sát giáo, Mông Sơn tứ hữu làm theo chỉ huy của Hàn Lập, lập vòng phòng hộ và chịu sức ép trực tiếp từ Huyết Thị. Phòng hộ liên hợp của họ bị quyền huyết sắc đánh lõm, khiến Hàn Lập phải dùng Bạch Lân thuẫn hỗ trợ.","nguon":["@c0307"]},{"id":"chanh-ma-luong-dao","name":"Chánh, ma lưỡng đạo","cn":"","type":"phe-tu-tien","typeLabel":"Hai phe tu tiên","diaBan":"Không rõ","nhanVatChinh":[],"blurb":"Chánh, ma lưỡng đạo được nhắc là hai phe từng cùng truy sát người sở hữu Huyết Tế ma công. Nguyên nhân là tà pháp này thôn phệ tinh huyết và tu vi của tu sĩ khác, khiến mọi người kiêng kị.","detail":"Hàn Lập nói những người tu Huyết Tế ma công từng bị cả hai phe chính đạo và ma đạo truy sát. Điều này cho thấy Huyết tế tuy tăng pháp lực nhanh nhưng trở thành cấm kỵ trong giới tu tiên vì trực tiếp đe dọa các tu sĩ khác.","nguon":["@c0311"]},{"id":"tu-dai-huyet-thi","name":"Tứ đại huyết thị","cn":"","type":"nhom-doi-dich","typeLabel":"Nhóm đối địch","diaBan":"Hoàng cung Việt quốc","nhanVatChinh":["Thanh Văn đạo sĩ","Ngô Cửu Chỉ","Băng Yêu","Thiết La"],"blurb":"Bốn Huyết thị đối đầu nhóm Hoàng Phong cốc trong trận tại hoàng cung Việt quốc.","detail":"Tứ đại huyết thị gồm Thanh Văn đạo sĩ, Ngô Cửu Chỉ, Băng Yêu và Thiết La. Khi Thanh Văn phát tín hiệu, bốn người tụ lại, được phía Hoàng Phong cốc nhận định khó đối phó hơn tu sĩ Trúc Cơ bình thường, rồi cùng phát hào quang đỏ máu để bắt đầu Yêu hóa.","nguon":["@c0319"]},{"id":"dai-gia-toc-tu-tien-cua-luu-tinh","name":"Đại gia tộc tu tiên của Lưu Tĩnh","cn":"","aliases":[],"type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Không rõ","nhanVatChinh":["Lưu Tĩnh"],"blurb":"Gia tộc tu tiên mà Lưu Tĩnh xuất thân. Khi Lưu Tĩnh còn nhỏ bị tà tu bắt đi ngược đãi, người trong gia tộc đã cứu hắn ra.","detail":"Chương hé lộ Lưu Tĩnh vốn xuất thân từ một đại gia tộc tu tiên. Biến cố bị tà tu bắt cóc lúc nhỏ và được người nhà cứu thoát trở thành một phần nguồn gốc cho lòng căm hận tà tu của hắn, trước khi hắn bái nhập môn hạ Lý Hóa Nguyên.","nguon":["@c0322"]},{"id":"hoang-cung-viet-quoc-phe-viet-hoang","name":"Hoàng cung Việt quốc / phe Việt hoàng","cn":"","type":"the-luc","typeLabel":"Thế lực hoàng cung / tà tu","diaBan":"Hoàng cung Việt quốc","nhanVatChinh":["Việt hoàng","Hắc Sát giáo chủ","Băng Yêu","Hai gã Huyết thị bị hỏa điểu luyện hóa"],"blurb":"Phe đối địch với nhóm Hoàng Phong cốc trong biến cố huyết tế tại hoàng cung Việt quốc.","detail":"Việt hoàng và Lam bào nhân cho thấy cùng một hệ thống huyết tế, huyết thị và Ngũ hành huyết ngưng đan. Trong chương này, phe này lộ thủ đoạn che giấu tu vi, hấp nạp huyết quang và khả năng chống chịu vượt mức tu sĩ Trúc Cơ thông thường.","nguon":["@c0325"]},{"id":"hoang-thanh-viet-quoc-phe-hoang-cung","name":"Hoàng thành Việt quốc","cn":"","type":"dia-ban","typeLabel":"Địa bàn quyền lực","diaBan":"Hoàng thành Việt quốc","nhanVatChinh":["Việt hoàng","Hàn Lập"],"blurb":"Địa bàn quyền lực nơi Việt Hoàng đang bị nhóm Hàn Lập uy hiếp trực tiếp.","detail":"Trong cuộc truy kích tại hoàng thành, Việt Hoàng nhận ra sự việc đã tới mức không thể để nhóm Hàn Lập rời khỏi nơi này, đồng thời nảy sinh ý nghĩ ngôi hoàng đế Việt quốc của mình khó giữ được nếu thất bại.","nguon":["@c0327"]},{"id":"ma-dao-luc-tong","name":"Ma đạo lục tông","aliases":[],"cn":"","type":"lien-minh","typeLabel":"Liên minh ma đạo","diaBan":"","nhanVatChinh":[],"blurb":"Liên minh sáu tông Ma đạo đang đối đầu với Thất phái. Họ đã hạ chiến thư, hẹn hai tháng sau quyết chiến.","detail":"Ma đạo lục tông đã định thời hạn quyết chiến với Thất phái sau hai tháng. Kế hoạch tiềm nhập thế tục Việt quốc để gây sóng gió cũng được nói là đã hủy bỏ không rõ nguyên nhân.","trangThai":"Chuẩn bị quyết chiến với Thất phái","quanHe":"Đối địch Thất phái","capNhatToi":"@c0331","tabs":{"tienTrinh":[{"chuong":"@c0331","loai":"khai chiến","importance":"major","giaiDoan":"Hạ chiến thư","text":"Ma đạo lục tông đã hạ chiến thư và hẹn hai tháng sau quyết chiến với Thất phái.","anchor":"hai tháng sau Ma đạo lục tông cùng với chúng ta quyết một trận thư hùng"}]},"nguon":["@c0331"]},{"id":"tu-binh-bang","name":"Tứ Bình bang","cn":"","type":"bang-phai","typeLabel":"Bang phái thế tục","diaBan":"Gia Nguyên thành","nhanVatChinh":["Tôn Nhị Cẩu","Khúc Hồn","Hàn Lập"],"blurb":"Bang phái thế tục do Hàn Lập để lại làm đường lui ở Gia Nguyên thành. Tôn Nhị Cẩu kinh doanh bang này trong nhiều năm, có Khúc Hồn hiệp trợ.","detail":"Khi quay lại Gia Nguyên thành, Hàn Lập muốn xem Tôn Nhị Cẩu kinh doanh Tứ Bình bang như thế nào. Hắn nhớ rằng trong những năm gần đây Khúc Hồn đã hiệp trợ, nên kỳ vọng bang phái này có chút thành tựu.","quyMo":"Đang được kinh doanh nhiều năm tại Gia Nguyên thành","quanHe":"Là đường lui thế tục Hàn Lập lưu lại năm xưa","trangThai":"đang hoạt động","thanhVien":[{"ten":"Tôn Nhị Cẩu","chucVu":"Người kinh doanh bang phái","tuChuong":"@c0332","trangThai":"đang hoạt động"},{"ten":"Khúc Hồn","chucVu":"Người hiệp trợ","tuChuong":"@c0332","trangThai":"được nhắc là từng hỗ trợ"}],"tabs":{"tienTrinh":[{"chuong":"@c0332","loai":"nhắc tới","importance":"normal","giaiDoan":"Đường lui được kiểm tra","text":"Hàn Lập quay lại Gia Nguyên thành và muốn kiểm tra việc Tôn Nhị Cẩu kinh doanh Tứ Bình bang dưới sự hiệp trợ của Khúc Hồn.","anchor":"còn phải muốn đi nhìn xem Tôn Nhị Cẩu kinh doanh Tứ Bình bang như thế nào","trangThaiMoc":"đang được Hàn Lập chú ý"}]},"capNhatToi":"@c0332","nguon":["@c0332"]},{"id":"nam-phai-con-lai","name":"Năm phái còn lại","cn":"","type":"lien-minh","typeLabel":"Nhóm thế lực","diaBan":"Việt Quốc","nhanVatChinh":[],"blurb":"Nhóm năm phái còn lại trong Thất phái sau khi tách Hoàng Phong Cốc khỏi cách gọi. Theo Lệnh Hồ lão tổ, họ sẽ cùng Hoàng Phong Cốc tiến thoái và rút khỏi Việt Quốc.","detail":"Trong buổi triệu tập tại Nghị Sự điện, Lệnh Hồ lão tổ cho biết không chỉ Hoàng Phong Cốc mà năm phái còn lại cũng sẽ cùng tiến thoái. Mục tiêu là rời Việt Quốc để bảo toàn lực lượng, chờ ngày Đông Sơn tái khởi.","trangThai":"chuẩn bị rút khỏi Việt Quốc","quanHe":[{"ten":"Hoàng Phong Cốc","quanHe":"cùng tiến thoái, cùng rút khỏi Việt Quốc"},{"ten":"Thất phái","quanHe":"thuộc liên minh Thất phái còn lại sau biến cố Linh Thú Sơn phản bội"}],"tabs":{"tienTrinh":[{"chuong":"@c0346","loai":"liên minh","importance":"normal","giaiDoan":"Cùng rút khỏi Việt Quốc","text":"Năm phái còn lại sẽ cùng Hoàng Phong Cốc tiến thoái, rời Việt Quốc để bảo toàn lực lượng và tìm cơ hội Đông Sơn tái khởi.","anchor":"năm phái còn lại sẽ cùng chúng ta tiến thoái"}]},"capNhatToi":"@c0346","nguon":["@c0346"]},{"id":"doi-ma-dao-canh-bien-gioi-viet-nguyen-vu","name":"Đội Ma đạo canh biên giới Việt — Nguyên Vũ","cn":"","aliases":[],"type":"doi-ngu","typeLabel":"Đội truy sát","diaBan":"Biên giới Việt Quốc — Nguyên Vũ Quốc","nhanVatChinh":[],"blurb":"Đội Ma đạo canh biên giới Việt — Nguyên Vũ là lực lượng hơn vài chục tu sĩ xuất hiện sau khi Hàn Lập vượt biên. Họ đồn trú tại khu vực này để giám sát và chặn giết tu sĩ tiếp tục trốn sang Nguyên Vũ Quốc.","detail":"Nửa ngày sau khi Hàn Lập đưa Khúc Hồn vào Nguyên Vũ Quốc, một đội ngũ Ma đạo hơn vài chục người xuất hiện và đóng lại tại biên giới. Nhiệm vụ của họ là kiểm soát khu vực liên miên mấy trăm dặm, tiêu diệt những tu sĩ muốn vượt biên trốn khỏi Việt Quốc.","trangThai":"đồn trú biên giới","quanHe":"Thuộc phe Ma đạo trong chiến dịch truy sát tu sĩ Việt Quốc.","capNhatToi":"@c0349","tabs":{"tienTrinh":[{"chuong":"@c0349","loai":"mở rộng/mất địa bàn","importance":"normal","giaiDoan":"Lập tuyến chặn biên","trangThaiMoc":"đồn trú","text":"Đội ngũ Ma đạo hơn vài chục người xuất hiện và đồn trú tại biên giới Việt Quốc — Nguyên Vũ Quốc để chặn giết tu sĩ đến sau muốn trốn sang Nguyên Vũ Quốc.","anchor":"liền có đội ngũ Ma đạo hơn vài chục người cũng xuất hiện và đồn trú tại nơi đây"}]},"nguon":["@c0349"]},{"id":"minh-dao","name":"Minh đạo","cn":"","aliases":[],"type":"lien-minh","typeLabel":"Thế lực chính đạo","diaBan":"Thiên Nam","nhanVatChinh":[],"blurb":"Minh đạo được Hàn Lập nhắc tới như đối thủ tương lai của Ma đạo lục tông. Theo suy đoán của hắn, sau khi Ma đạo thôn tính vài nước, hai phe có thể sẽ bước vào quyết chiến.","detail":"Trong lúc tính đường rời khỏi Việt Quốc, Hàn Lập suy đoán Ma đạo lục tông sau khi tiêu hóa tu tiên giới Việt Quốc và thôn tính thêm vài nước có thể chỉnh đốn lực lượng để quyết chiến với Minh đạo. Chương này chỉ cho thấy Minh đạo qua nhận định chiến lược của Hàn Lập.","trangThai":"đối thủ tương lai của Ma đạo","capNhatToi":"@c0349","nguon":["@c0349"]},{"id":"pho-gia","name":"Phó gia","cn":"","aliases":[],"type":"gia-toc","typeLabel":"Tu tiên gia tộc","diaBan":"Nguyên Vũ quốc","nhanVatChinh":["Lão giả Phó gia","Người thành niên Phó gia"],"blurb":"Một đại gia tộc có thanh danh hiển hách tại Nguyên Vũ quốc. Hai tu sĩ Phó gia liên quan việc phá nơi ở Tề Vân Tiêu và truy cứu chuyện người Phó gia bị giết, nhưng đều bị Hàn Lập thuấn sát.","detail":"Phó gia xuất hiện qua hai thành viên đối đầu Hàn Lập tại nơi ở bị phá của Tề Vân Tiêu. Người thành niên Phó gia nói Tề Vân Tiêu đã giết người của Phó gia nên đáng chết, cho thấy mâu thuẫn giữa gia tộc này và Tề Vân Tiêu.","nguonGoc":"Đại gia tộc ở Nguyên Vũ quốc","quyMo":"Một trong những đại gia tộc thanh danh hiển hách tại Nguyên Vũ quốc","quanHe":"Đối địch với Tề Vân Tiêu trong vụ người Phó gia bị giết; hai tu sĩ Phó gia bị Hàn Lập giết tại nơi ở của Tề Vân Tiêu.","trangThai":"hai tu sĩ xuất hiện trong chương đã chết @c0350","thanhVien":[{"ten":"Lão giả Phó gia","chucVu":"tu sĩ Trúc Cơ trung kỳ","tuChuong":"@c0350","trangThai":"đã chết"},{"ten":"Người thành niên Phó gia","chucVu":"tu sĩ Phó gia","tuChuong":"@c0350","trangThai":"đã chết"}],"tabs":{"tienTrinh":[{"chuong":"@c0350","loai":"nhắc tới","importance":"normal","giaiDoan":"Truy sát Tề Vân Tiêu","text":"Phó gia được nêu là đại gia tộc nổi tiếng ở Nguyên Vũ quốc, có hai tu sĩ liên quan vụ phá nơi ở Tề Vân Tiêu và đều bị Hàn Lập giết.","anchor":"gia tộc của hắn là một trong những đại gia tộc thanh danh hiển hách tại Nguyên Vũ quốc","trangThaiMoc":"mất hai tu sĩ trong xung đột với Hàn Lập"}]},"capNhatToi":"@c0350","nguon":["@c0350"]},{"id":"te-gia","name":"Tề gia","cn":"","aliases":[],"type":"gia-toc","typeLabel":"Tu tiên gia tộc","diaBan":"Không rõ","nhanVatChinh":["Tề Vân Tiêu"],"blurb":"Gia tộc của Tề Vân Tiêu, được Phó gia nhắc đến khi đối chất với Hàn Lập. Trong mắt người Phó gia, Tề Vân Tiêu chỉ là đệ tử ngoại hệ nên Tề gia khó vì hắn mà đối đầu Phó gia.","detail":"Tề gia chưa trực tiếp xuất hiện trong chương, nhưng được dùng để nhấn mạnh thân phận ngoại hệ của Tề Vân Tiêu và thế cân nhắc giữa các gia tộc tu tiên.","quanHe":"Có Tề Vân Tiêu là đệ tử ngoại hệ; bị Phó gia cho rằng sẽ không vì Tề Vân Tiêu mà chống Phó gia.","thanhVien":[{"ten":"Tề Vân Tiêu","chucVu":"đệ tử ngoại hệ","tuChuong":"@c0350","trangThai":"còn sống"}],"tabs":{"tienTrinh":[{"chuong":"@c0350","loai":"nhắc tới","importance":"bridge","giaiDoan":"Liên hệ với Tề Vân Tiêu","text":"Tề gia được Phó gia nhắc đến như gia tộc của Tề Vân Tiêu, nhưng Tề Vân Tiêu chỉ là đệ tử ngoại hệ.","anchor":"Tề gia như thế nào lại vì một đệ tử ngoại hệ đi chống lại Phó gia chúng ta","trangThaiMoc":"được nhắc qua thân phận Tề Vân Tiêu"}]},"capNhatToi":"@c0350","nguon":["@c0350"]},{"id":"tinh-tran-cac","name":"Tinh Trần các","cn":"","aliases":[],"type":"cua-hieu","typeLabel":"Cửa hiệu tu tiên","diaBan":"Trung tâm phường thị","nhanVatChinh":["Phụ nhân trung niên chưởng quầy tầng năm Tinh Trần các","Nhân viên phục vụ Tinh Trần các tầng một","Gã sai vặt áo đỏ canh cầu thang tầng sáu","Tử Liên"],"blurb":"Tinh Trần các là cửa hiệu lớn ở trung tâm phường thị Nguyên Vũ quốc. Lâu các chia chín tầng, phân khách theo cảnh giới và nắm giữ trân phẩm dành cho tu sĩ cấp cao.","detail":"Tinh Trần các có bảy tầng đầu mở cửa cho khách ngoài, trong đó tầng một đến ba phục vụ tu sĩ cấp thấp, tầng bốn đến sáu phục vụ tu sĩ cấp cao, còn tầng bảy chỉ mở cho tu sĩ Kết Đan kỳ. Hàn Lập đến đây sau khi dạo phường thị vì cho rằng cửa hiệu lớn dễ có vật quý.","quyMo":"Chín tầng","trangThai":"đang hoạt động","thanhVien":[{"ten":"Phụ nhân trung niên chưởng quầy tầng năm Tinh Trần các","chucVu":"Chưởng quầy tầng năm","tuChuong":"@c0353","trangThai":"đang phục vụ"},{"ten":"Nhân viên phục vụ Tinh Trần các tầng một","chucVu":"Nhân viên tầng một","tuChuong":"@c0353","trangThai":"đang phục vụ"},{"ten":"Gã sai vặt áo đỏ canh cầu thang tầng sáu","chucVu":"Người canh cầu thang","tuChuong":"@c0353","trangThai":"đang phục vụ"},{"ten":"Tử Liên","chucVu":"Nha hoàn","tuChuong":"@c0353","trangThai":"đang phục vụ"}],"tabs":{"tienTrinh":[{"chuong":"@c0353","loai":"nhắc tới","importance":"normal","giaiDoan":"Lộ cơ cấu phân tầng","text":"Tinh Trần các được giới thiệu là cửa hiệu chín tầng, phân khu tiếp khách theo cảnh giới và có trân phẩm cho tu sĩ cấp cao.","anchor":"Tinh Trần các này tổng cộng chia làm chín tâng"}]},"capNhatToi":"@c0353","nguon":["@c0353"]},{"id":"sau-phai-viet-quoc","name":"Sáu phái Việt quốc","cn":"","type":"lien-minh","typeLabel":"Liên minh môn phái","diaBan":"Việt quốc","nhanVatChinh":["Hàn Lập"],"blurb":"Liên minh sáu phái tu tiên ở Việt quốc, bị Ma đạo đánh bại và phải triệt ly khỏi quê hương. Một phần tu sĩ còn ở lại dựa địa thế tập kích Ma đạo, khiến việc tiếp quản Việt quốc chưa hoàn toàn ổn định.","detail":"Sau đại bại trước Ma đạo, sáu phái Việt quốc phải rút khỏi quê hương. Trong quá trình triệt ly, có phái bỏ lại đệ tử không tinh nhuệ để che mắt địch, còn các trọng địa phần lớn đã bị công phá, tài vật quý giá được đệ tử rút lui mang đi phần lớn.","trangThai":"suy bại, triệt ly khỏi Việt quốc","capNhatToi":"@c0357","tabs":{"tienTrinh":[{"chuong":"@c0357","loai":"suy","importance":"major","giaiDoan":"Đại bại trước Ma đạo","text":"Sáu phái Việt quốc bị Ma đạo đánh bại và phải triệt ly khỏi quê hương, trong khi một số tu sĩ còn ở lại tiếp tục tập kích người Ma đạo.","anchor":"chẳng những sáu phái Việt quốc phải triệt ly khỏi quê hương","trangThaiMoc":"suy bại, triệt ly"}]},"nguon":["@c0357"]},{"id":"dinh-gia","name":"Đinh gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"có sản nghiệp thế tục tại Việt quốc","nhanVatChinh":["Đinh lão giả"],"blurb":"Gia tộc tu tiên của Đinh lão giả, có nhiều sản nghiệp thế tục tại Việt quốc. Nhờ nguồn tin này, Đinh lão giả biết được tình hình mới sau khi sáu phái Việt quốc đại bại.","detail":"Đinh gia không trực tiếp xuất hiện tại Bạch Trì sơn, nhưng được Đinh lão giả nhắc đến như nguồn tin giúp ông nắm tình hình Việt quốc. Gia tộc có nhiều sản nghiệp thế tục mở tại Việt quốc nên nhận được tin tức về chiến sự, gia tộc tu tiên và các phái triệt ly.","thanhVien":[{"ten":"Đinh lão giả","chucVu":"thành viên Đinh gia","tuChuong":"@c0357","trangThai":"đang hoạt động"}],"trangThai":"đang hoạt động","capNhatToi":"@c0357","tabs":{"tienTrinh":[{"chuong":"@c0357","loai":"nhắc tới","importance":"normal","giaiDoan":"Nguồn tin Việt quốc","text":"Đinh gia được nhắc là gia tộc có nhiều sản nghiệp thế tục tại Việt quốc, nhờ đó truyền tin mới về cho Đinh lão giả.","anchor":"dù sao Đinh gia có rất nhiều sản nghiệp thế tục mở tại Việt quốc","trangThaiMoc":"đang hoạt động"}]},"nguon":["@c0357"]},{"id":"cac-gia-toc-tu-tien-viet-quoc","name":"Các gia tộc tu tiên Việt quốc","cn":"","type":"nhom-the-luc","typeLabel":"Nhóm gia tộc tu tiên","diaBan":"Việt quốc","nhanVatChinh":[],"blurb":"Nhóm các gia tộc tu tiên tại Việt quốc sau đại bại của sáu phái. Họ phân hóa thành ba thái độ: quy thuận Ma đạo, rút theo sáu phái hoặc tiếp tục quan sát.","detail":"Sau khi sáu phái Việt quốc đại bại, các gia tộc tu tiên trong nước không còn cùng một hướng đi. Một số chủ động quy thuận Ma đạo lục tông, một số theo sáu phái rời khỏi Việt quốc, số còn lại giữ thái độ quan sát tình thế.","trangThai":"phân hóa","capNhatToi":"@c0357","tabs":{"tienTrinh":[{"chuong":"@c0357","loai":"suy","importance":"normal","giaiDoan":"Phân hóa sau đại bại","text":"Các gia tộc tu tiên Việt quốc chia thành ba thái độ sau khi sáu phái đại bại trước Ma đạo.","anchor":"các gia tộc tu tiên ở Việt quốc hiện tại cũng chia làm ba loại thái độ","trangThaiMoc":"phân hóa"}]},"nguon":["@c0357"]},{"id":"thien-la-quoc","name":"Thiên La quốc","cn":"","type":"quoc-gia","typeLabel":"Quốc gia / địa bàn Ma đạo","diaBan":"Phía Đông Việt quốc","nhanVatChinh":[],"blurb":"Thiên La quốc là quốc gia nằm ở phía Đông Việt quốc, được mô tả là ổ của Ma đạo. Vì vị trí và thế lực chiếm giữ nơi này, Hàn Lập loại bỏ hướng Đông khi cân nhắc đường thoát thân.","detail":"Trong phân tích của Hàn Lập về đường rời Việt quốc, Thiên La quốc ở phía Đông là địa bàn của Ma đạo, khiến hướng này trở thành lựa chọn nguy hiểm. Sự hiện diện của Thiên La quốc cùng Phong Đô quốc tạo thế kẹp Đông Tây quanh Việt quốc.","quanHe":"Gắn với Ma đạo, đối trọng với Phong Đô quốc của Chính đạo minh quanh Việt quốc.","trangThai":"Địa bàn Ma đạo","tabs":{"tienTrinh":[{"chuong":"@c0358","loai":"nhắc tới","importance":"normal","giaiDoan":"Đường Đông bị loại bỏ","text":"Thiên La quốc được xác định là ổ của Ma đạo ở phía Đông Việt quốc, khiến Hàn Lập không chọn hướng này để rời đi.","anchor":"Bởi vì phương hướng Đông, Tây Việt quốc phân biệt là Thiên La quốc - ổ của Ma đạo"}]},"capNhatToi":"@c0358","dinhDanh":"goc","nguon":["@c0358"]},{"id":"phong-do-quoc","name":"Phong Đô quốc","cn":"","type":"quoc-gia","typeLabel":"Quốc gia / địa bàn Chính đạo minh","diaBan":"Phía Tây Việt quốc","nhanVatChinh":[],"blurb":"Phong Đô quốc là quốc gia phía Tây Việt quốc, thuộc phạm vi Chính đạo minh. Sự tồn tại của thế lực này khiến Hàn Lập không chọn đường Tây để tránh loạn.","detail":"Phong Đô quốc được nêu cùng Thiên La quốc khi Hàn Lập phân tích cục diện Đông Tây quanh Việt quốc. Vì phía Tây là địa bàn Chính đạo minh, hướng này cũng không thích hợp cho việc thoát khỏi vùng chiến sự.","quanHe":"Gắn với Chính đạo minh, đối trọng với Thiên La quốc của Ma đạo quanh Việt quốc.","trangThai":"Địa bàn Chính đạo minh","tabs":{"tienTrinh":[{"chuong":"@c0358","loai":"nhắc tới","importance":"normal","giaiDoan":"Đường Tây bị loại bỏ","text":"Phong Đô quốc được xác định là địa bàn của Chính đạo minh ở phía Tây Việt quốc, khiến đường thoát phía Tây không thích hợp.","anchor":"và Phong Đô quốc của Chính đạo minh, cho nên chỉ có thể đi theo hướng Nam hoặc Bắc"}]},"capNhatToi":"@c0358","dinhDanh":"goc","nguon":["@c0358"]},{"id":"chinh-dao-minh","name":"Chính đạo minh","cn":"","type":"lien-minh","typeLabel":"Thế lực chính đạo","diaBan":"Phong Đô quốc","nhanVatChinh":[],"blurb":"Chính đạo minh là thế lực ở Phong Đô quốc, cùng Ma đạo tạo áp lực lên khu vực quanh Việt quốc. Sự hiện diện của họ khiến các tiểu quốc phía Bắc có nguy cơ bị cuốn vào chiến trường.","detail":"Chính đạo minh được nhắc như một trong hai thế lực lớn cùng Ma đạo đang gây biến động quanh Việt quốc. Các tiểu quốc phía Bắc khó ngăn nổi hai thế lực này, thậm chí có nước đã dựa vào họ.","quanHe":"Đối trọng với Ma đạo, tạo thế kẹp và biến động quanh Việt quốc.","trangThai":"Đang gây ảnh hưởng khu vực","tabs":{"tienTrinh":[{"chuong":"@c0358","loai":"nhắc tới","importance":"normal","giaiDoan":"Gây áp lực khu vực","text":"Chính đạo minh cùng Ma đạo được Hàn Lập xem là mối đe dọa khiến các nước phía Bắc khó trở thành đường lui an toàn.","anchor":"Thậm chí trong bọn họ còn có quốc gia sớm đã ỷ trượng vào hai thế lực lớn này"}]},"capNhatToi":"@c0358","dinhDanh":"goc","nguon":["@c0358"]},{"id":"cuu-quoc-minh","name":"Cửu quốc minh","cn":"","type":"lien-minh","typeLabel":"Liên minh tu tiên chín quốc gia","diaBan":"Chín quốc gia nhỏ phía Nam tuyến Việt quốc","nhanVatChinh":[],"blurb":"Cửu quốc minh là liên minh thân mật của chín quốc gia nhỏ, do Tu tiên giới địa phương lập ra để chống pháp sĩ Mộ Lan. Hàn Lập suy đoán lục phái Việt quốc sau khi triệt ly có khả năng nương nhờ nơi này.","detail":"Cửu quốc minh hình thành từ chín quốc gia nhỏ ở phía Nam, nhằm đối phó đại quân pháp sĩ Mộ Lan tộc. Sau những thất bại ban đầu, Tu tiên giới cửu quốc kết minh, dùng thủ đoạn và quỷ kế để dần phản công, đoạt lại phần đất từng bị chiếm.","nguonGoc":"Do Tu tiên giới chín quốc gia lập ra để chống pháp sĩ Mộ Lan.","tonChi":"Liên hợp đối kháng đại quân pháp sĩ Mộ Lan và bảo vệ tài nguyên tu luyện của chín quốc gia.","quyMo":"Chín quốc gia nhỏ","quanHe":"Đối địch Mộ Lan tộc; có thể tiếp nhận trợ lực từ lục phái Việt quốc.","trangThai":"dàn xếp với lục đạo tông phái @c0363","tabs":{"tienTrinh":[{"chuong":"@c0358","loai":"lập","importance":"major","giaiDoan":"Liên minh chống Mộ Lan","text":"Cửu quốc minh được giới thiệu là liên minh của chín quốc gia nhỏ, lập ra để chống đại quân pháp sĩ Mộ Lan.","anchor":"Còn lại là chín quốc gia nhỏ tạo thành một liên minh cực kỳ thân mật gọi là “Cửu quốc minh”."},{"chuong":"@c0363","loai":"liên minh","importance":"normal","giaiDoan":"Dàn xếp lục đạo","trangThaiMoc":"dàn xếp công việc","text":"Cửu Quốc Minh dàn xếp công việc với lục đạo tông phái sau khi các tông phái này rời nước cũ.","anchor":"tu sĩ lục đạo tông phái ở nước hắn rốt cục cũng dàn xếp được công việc với Cửu Quốc Minh"}]},"capNhatToi":"@c0358","dinhDanh":"goc","nguon":["@c0358","@c0363"]},{"id":"mo-lan-toc","name":"Mộ Lan tộc","cn":"","type":"dan-toc","typeLabel":"Dân tộc du mục / thế lực thảo nguyên","diaBan":"Mộ Lan đại thảo nguyên","nhanVatChinh":["Pháp sĩ Mộ Lan tộc"],"blurb":"Mộ Lan tộc là dân tộc du mục sống trên Mộ Lan đại thảo nguyên, có nhiều bộ lạc và pháp sĩ. Vì thiếu tài nguyên tu luyện, pháp sĩ của họ từng nhòm ngó linh mạch và mỏ linh thạch của chín quốc gia, dẫn đến chiến tranh lâu dài.","detail":"Mộ Lan tộc sống trên đại thảo nguyên rộng lớn, tài nguyên tu luyện nghèo nàn nhưng có hệ thống pháp sĩ riêng. Do nhu cầu linh mạch và mỏ linh thạch, nhóm pháp sĩ Mộ Lan từng xâm chiếm tài nguyên của chín quốc gia bên cạnh, khiến họ trở thành đối thủ lớn của Cửu quốc minh.","quyMo":"Nhiều bộ lạc du mục lớn nhỏ","quanHe":"Đối địch Cửu quốc minh; tử chiến nhiều đời với Đột Ngột nhân.","trangThai":"Đang đối kháng Cửu quốc minh và Đột Ngột nhân","tabs":{"tienTrinh":[{"chuong":"@c0358","loai":"khai chiến","importance":"normal","giaiDoan":"Tranh đoạt tài nguyên","text":"Mộ Lan tộc được giới thiệu là dân tộc du mục có pháp sĩ nhòm ngó tài nguyên tu luyện của chín quốc gia bên cạnh, dẫn tới xung đột lâu dài.","anchor":"nhóm pháp sĩ của Mộ Lan tộc liền nhòm ngó qua chín quốc gia bên cạnh với nguồn tài nguyên phong phú"}]},"capNhatToi":"@c0358","dinhDanh":"goc","nguon":["@c0358"]},{"id":"phap-si-mo-lan-toc","name":"Pháp sĩ Mộ Lan tộc","cn":"","type":"nhom-tu-tien-gia","typeLabel":"Nhóm tu tiên giả Mộ Lan","diaBan":"Mộ Lan đại thảo nguyên","nhanVatChinh":[],"blurb":"Pháp sĩ Mộ Lan tộc là nhóm tu tiên giả của người Mộ Lan, được tôn xưng là pháp sĩ thay vì tu sĩ. Trước Kết Đan, họ ít chú trọng pháp khí, phù lục mà chuyên luyện ngũ hành đạo thuật và Linh thuật.","detail":"Pháp sĩ Mộ Lan tộc là lực lượng tu luyện nòng cốt của Mộ Lan tộc. Họ phát triển Linh thuật từ ngũ hành đạo thuật và bí thuật thảo nguyên, nhờ đó có ưu thế khi chiến đấu với tu sĩ cùng cấp.","tonChi":"Tu luyện hệ pháp thuật riêng của Mộ Lan tộc và tham chiến vì tài nguyên tu luyện.","caoThuManhNhat":"Không rõ","quanHe":"Thuộc Mộ Lan tộc, đối địch Tu tiên giới cửu quốc và Cửu quốc minh.","trangThai":"Lực lượng chủ chiến của Mộ Lan tộc","tabs":{"tienTrinh":[{"chuong":"@c0358","loai":"nhắc tới","importance":"normal","giaiDoan":"Hệ pháp sĩ Mộ Lan","text":"Pháp sĩ Mộ Lan tộc được giới thiệu là tu tiên giả của người Mộ Lan, có cách gọi và hệ tu luyện khác tu sĩ thông thường.","anchor":"chỉ có điều người Mộ Lan không gọi bọn họ là tu sĩ mà tôn xưng là “Pháp sĩ”"}]},"capNhatToi":"@c0358","dinhDanh":"goc","nguon":["@c0358"]},{"id":"tu-tien-gioi-cuu-quoc","name":"Tu tiên giới cửu quốc","cn":"","type":"lien-minh","typeLabel":"Tu tiên giới chín quốc gia","diaBan":"Chín quốc gia phía Nam","nhanVatChinh":[],"blurb":"Tu tiên giới cửu quốc là lực lượng tu tiên của chín quốc gia phía Nam, ban đầu từng chống Mộ Lan riêng lẻ rồi thất bại. Sau khi rút kinh nghiệm, họ kết thành Cửu quốc minh để phản công pháp sĩ Mộ Lan.","detail":"Trong lịch sử xung đột với pháp sĩ Mộ Lan, Tu tiên giới cửu quốc từng mất nhiều lãnh thổ và tài nguyên vì chống đỡ rời rạc. Sau đó họ kết minh, dùng thủ đoạn và quỷ kế để từng bước đánh bại pháp sĩ Mộ Lan, đoạt lại đất bị chiếm.","nguonGoc":"Các tu tiên giới địa phương của chín quốc gia nhỏ.","quanHe":"Lập Cửu quốc minh; đối địch pháp sĩ Mộ Lan tộc.","trangThai":"Đã kết thành Cửu quốc minh","tabs":{"tienTrinh":[{"chuong":"@c0358","loai":"liên minh","importance":"major","giaiDoan":"Kết thành Cửu quốc minh","text":"Sau khi thất bại trước pháp sĩ Mộ Lan, Tu tiên giới cửu quốc kết thành Cửu quốc minh để phản công và đoạt lại phần đất bị chiếm.","anchor":"Sau khi biết đối thủ lợi hại, Tu tiên giới cửu quốc vội vàng rút ra bài học kinh nghiệm, kết thành “Cửu quốc minh”"}]},"capNhatToi":"@c0358","dinhDanh":"goc","nguon":["@c0358"]},{"id":"dot-ngot-nhan","name":"Đột Ngột nhân","cn":"","type":"dan-toc","typeLabel":"Dân tộc du mục thảo nguyên","diaBan":"Thiên Lan thảo nguyên","nhanVatChinh":[],"blurb":"Đột Ngột nhân là dân tộc du mục ở đầu kia thảo nguyên, đối địch sinh tử với Mộ Lan tộc. Họ gắn với tín ngưỡng Thiên Lan thú và nhiều đời giao chiến với người Mộ Lan.","detail":"Đột Ngột nhân được nhắc như thế lực đối địch ở đầu kia Mộ Lan thảo nguyên. Quan hệ giữa họ và Mộ Lan tộc là ngươi chết ta sống, dù cùng là dân tộc du mục sống trên một khối thảo nguyên.","tonChi":"Tin thờ Thiên Lan thú","quanHe":"Đối địch sinh tử với Mộ Lan tộc.","trangThai":"Đang đối địch Mộ Lan tộc","tabs":{"tienTrinh":[{"chuong":"@c0358","loai":"nhắc tới","importance":"normal","giaiDoan":"Đối trọng Mộ Lan","text":"Đột Ngột nhân được nhắc là thế lực đối địch của Mộ Lan tộc ở đầu kia thảo nguyên.","anchor":"Ở đầu kia còn có một thế lực đối địch của bọn họ - đó chính là “Đột Ngột nhân”."}]},"capNhatToi":"@c0358","dinhDanh":"goc","nguon":["@c0358"]},{"id":"dai-de-quoc-khong-lo-o-dau-kia-thao-nguyen","name":"Đại đế quốc khổng lồ ở đầu kia thảo nguyên","cn":"","type":"quoc-gia","typeLabel":"Quốc gia trong tin đồn","diaBan":"Đầu kia thảo nguyên","nhanVatChinh":[],"blurb":"Một đại đế quốc khổng lồ được đồn tồn tại ở đầu kia thảo nguyên, có diện tích lớn hơn rất nhiều so với toàn bộ khu Thiên Nam. Hàn Lập nghe tin nhưng không tin lời đồn này.","detail":"Đại đế quốc khổng lồ chỉ xuất hiện dưới dạng lời đồn trong những thông tin Hàn Lập nghe được. Quy mô được đồn là vượt xa khu Thiên Nam, nhưng độ tin cậy chưa được xác nhận trong nhận định của Hàn Lập.","quyMo":"Tin đồn lớn hơn khu Thiên Nam rất nhiều","trangThai":"Tin đồn chưa xác nhận","tabs":{"tienTrinh":[{"chuong":"@c0358","loai":"nhắc tới","importance":"bridge","giaiDoan":"Lời đồn xa xôi","text":"Một đại đế quốc khổng lồ ở đầu kia thảo nguyên được nhắc tới như lời đồn mà Hàn Lập không tin.","anchor":"ở một đầu khác của thảo nguyên còn có một đại đế quốc khổng lồ khó có thể tưởng tượng được"}]},"capNhatToi":"@c0358","dinhDanh":"goc","nguon":["@c0358"]},{"id":"luc-phai-viet-quoc","name":"Lục phái Việt quốc","cn":"","type":"lien-minh-tong-mon","typeLabel":"Nhóm sáu phái Việt quốc","diaBan":"Việt quốc","nhanVatChinh":["Hoàng Phong Cốc"],"blurb":"Lục phái Việt quốc là nhóm sáu môn phái chính đạo đã triệt ly khỏi Việt quốc trong cục diện loạn chiến. Hàn Lập suy đoán họ có thể tới Cửu quốc minh vì nơi đó cần thêm trợ lực chống pháp sĩ Mộ Lan.","detail":"Trong cân nhắc đường đi phía Nam, Hàn Lập cho rằng lục phái Việt quốc có khả năng không dừng ở các nước phụ cận mà sẽ đến Cửu quốc minh. Điều này khiến hắn lo nếu đi theo hướng Nam, mình dễ trở lại làm môn hạ Hoàng Phong Cốc và bị dùng làm vật hi sinh.","quanHe":"Có thể nương nhờ Cửu quốc minh; gồm Hoàng Phong Cốc trong nhóm sáu phái.","trangThai":"Đã triệt ly khỏi Việt quốc","tabs":{"tienTrinh":[]},"capNhatToi":"@c0358","dinhDanh":"goc","nguon":["@c0358"]},{"id":"thien-dao-hoi","name":"Thiên đạo hội","cn":"","type":"lien-minh","typeLabel":"Liên minh thế lực","diaBan":"Thiên Nam","nhanVatChinh":[],"blurb":"Liên minh do các đế quốc còn lại lập ra sau khi Hàn Lập rời Thiên Nam. Thiên đạo hội đối kháng sự bành trướng của cả ma đạo và chính đạo, hình thành thế lực thứ ba.","detail":"Một hai năm sau biến cố Hàn Lập truyền tống rời Thiên Nam, các đế quốc còn lại liên hợp thành Thiên đạo hội. Sự xuất hiện của liên minh này tạo thế chân vạc với chính đạo và ma đạo, khiến chiến sự trong Thiên Nam kéo dài chưa phân thắng bại.","trangThai":"thành lập @c0363","quyMo":"Các đế quốc còn lại liên hợp","capNhatToi":"@c0363","tabs":{"tienTrinh":[{"chuong":"@c0363","loai":"lập","importance":"major","giaiDoan":"Thế lực thứ ba","trangThaiMoc":"thành lập","text":"Các đế quốc còn lại liên hợp lập Thiên đạo hội để đối kháng chính đạo và ma đạo, tạo thành thế lực thứ ba ở Thiên Nam.","anchor":"các đế quốc còn lại liền liên hợp lại tạo thành ‘Thiên đạo hội’, tạo thành thế lực thứ 3"}]},"nguon":["@c0363"]},{"id":"chinh-dao","name":"Chính đạo","cn":"","type":"khoi-the-luc","typeLabel":"Khối thế lực","diaBan":"Thiên Nam","nhanVatChinh":[],"blurb":"Một trong các khối thế lực lớn tại Thiên Nam trong giai đoạn hậu biến cố. Chính đạo được nêu cùng ma đạo là đối tượng mà Thiên đạo hội phải đối kháng.","detail":"Sau khi Hàn Lập rời Thiên Nam, các đế quốc còn lại lập Thiên đạo hội để đối kháng sự bành trướng của ma đạo và chính đạo. Chính đạo vì vậy là một trong các cực thế lực trong thế chân vạc về sau.","trangThai":"đối đầu với Thiên đạo hội @c0363","capNhatToi":"@c0363","tabs":{"tienTrinh":[{"chuong":"@c0363","loai":"nhắc tới","importance":"normal","giaiDoan":"Đối kháng Thiên đạo hội","trangThaiMoc":"bị Thiên đạo hội đối kháng","text":"Chính đạo được nhắc là một trong hai lực lượng mà Thiên đạo hội được lập ra để đối kháng.","anchor":"để đối kháng sự bành trướng của ma đạo và chính đạo"}]},"nguon":["@c0363"]},{"id":"luc-dao-tong-phai","name":"Lục đạo tông phái","cn":"","type":"khoi-tong-phai","typeLabel":"Khối tông phái","diaBan":"Thiên Nam, chín nước","nhanVatChinh":["Lý Hóa Nguyên"],"blurb":"Khối tông phái rời nước cũ và dàn xếp với Cửu Quốc Minh. Về sau họ tranh linh mạch, linh quáng, địa bàn an thân và có nhiều tu sĩ chết trận trong chiến sự với Pháp Sĩ.","detail":"Sau khi dàn xếp với Cửu Quốc Minh, lục đạo tông phái không thể tiêu dao tại Việt quốc như trước. Họ phải tranh đoạt linh mạch, linh quáng và địa bàn, đồng thời đối diện nguy cơ Mộ Lan gia tộc xâm chiếm chín nước; trong các cuộc tranh đấu về sau, không ít tu sĩ Trúc Cơ và cả Kết Đan chết trận.","trangThai":"tranh địa bàn và tham chiến @c0363","capNhatToi":"@c0363","tabs":{"tienTrinh":[{"chuong":"@c0363","loai":"mở rộng/mất địa bàn","importance":"normal","giaiDoan":"Dàn xếp và tranh chấp","trangThaiMoc":"tranh địa bàn","text":"Lục đạo tông phái dàn xếp với Cửu Quốc Minh nhưng tiếp tục tranh linh mạch, linh quáng, địa bàn an thân và đối diện mối họa Mộ Lan.","anchor":"không ít tu sĩ Trúc cơ kì, thậm chí một vài tu sĩ Kết đan kỳ đã chết trận"}]},"nguon":["@c0363"]},{"id":"mo-lan-gia-toc","name":"Mộ Lan gia tộc","cn":"","type":"nhom-ngoai-dich","typeLabel":"Nhóm ngoại địch","diaBan":"Ngoài chín nước","nhanVatChinh":[],"blurb":"Lực lượng được nhắc như mối đe dọa có thể xâm chiếm chín nước. Sự tồn tại của họ khiến lục đạo tông phái phải xuất lực đối phó sau khi dàn xếp với Cửu Quốc Minh.","detail":"Trong hậu diễn biến Thiên Nam, Mộ Lan gia tộc được nêu như mối đe dọa đối với địa bàn chín nước. Nếu tu sĩ Mộ Lan muốn xâm chiếm nơi này, lục đạo tông phái cũng buộc phải xuất lực.","trangThai":"đe dọa chín nước @c0363","capNhatToi":"@c0363","tabs":{"tienTrinh":[{"chuong":"@c0363","loai":"nhắc tới","importance":"normal","giaiDoan":"Uy hiếp chín nước","trangThaiMoc":"đe dọa xâm chiếm","text":"Mộ Lan gia tộc được nhắc như lực lượng có khả năng xâm chiếm chín nước, buộc lục đạo tông phái phải xuất lực.","anchor":"nếu tuy sĩ của Mộ Lan gia tộc muốn xâm chiếm chín nước này thì tự nhiên bọn họ cũng phải xuất ra một ít lực"}]},"nguon":["@c0363"]}]};
